  select.innerHTML =
    `<option value="">Alle Quellen</option>` +
    quellen.map(quelle => `<option value="${quelle}">${quelle}</option>`).join("");

  if (Array.from(select.options).some(option => option.value === bisherigeAuswahl)) {
    select.value = bisherigeAuswahl;
  }
