  const warn = zutatenPruefen(zutaten);
  if (warn.length && !confirm("Bei den Zutaten gibt es mögliche Fehler:\n\n" + warn.join("\n") + "\n\nTrotzdem speichern?")) return;

  const alt = bearbeitungsIndex === null ? {} : rezepte[bearbeitungsIndex];

