      portionen: number151(label151(text, ["portionen"])),
      schwierigkeit: label151(text, ["schwierigkeit"]),
      zeit: label151(text, ["zubereitungszeit", "zeit"]),
      quelle: label151(text, ["quelle"]) || "Nicht zugeordnet",
