  // Alte Namen hart überschreiben.
  function rf155RezeptSpeichern() { return rf176LocalSaveRecipe(); }
  function rezeptSpeichernDirektCloud() { return rf176LocalSaveRecipe(); }
  function rezeptSpeichern() { return rf176LocalSaveRecipe(); }

  function cloudSpeichernAlle() { return rf176CloudSaveReplace(); }
  function cloudSpeichernAlleDirekt() { return rf176CloudSaveReplace(); }
  function cloudSpeichernAlleDirekt1294() { return rf176CloudSaveReplace(); }

  function cloudLaden() { return rf176CloudLoadOverwrite(); }
  function cloudHerunterladen() { return rf176CloudLoadOverwrite(); }
  function ausCloudLaden() { return rf176CloudLoadOverwrite(); }

  window.rf176LocalSaveRecipe = rf176LocalSaveRecipe;
  window.rf155RezeptSpeichern = rf176LocalSaveRecipe;
  window.rezeptSpeichernDirektCloud = rf176LocalSaveRecipe;
  window.rezeptSpeichern = rf176LocalSaveRecipe;

  window.rf176CloudSaveReplace = rf176CloudSaveReplace;
  window.cloudSpeichernAlle = rf176CloudSaveReplace;
  window.cloudSpeichernAlleDirekt = rf176CloudSaveReplace;
  window.cloudSpeichernAlleDirekt1294 = rf176CloudSaveReplace;

  window.rf176CloudLoadOverwrite = rf176CloudLoadOverwrite;
  window.cloudLaden = rf176CloudLoadOverwrite;
  window.cloudHerunterladen = rf176CloudLoadOverwrite;
