// =====================================================
// VERSION 1.77: Upload-Loop endgültig blockiert
// Cloud-Upload läuft nur noch über echten Button-Klick.
// Alte automatische cloudSpeichernAlle()-Aufrufe werden ignoriert.
// =====================================================

(function () {
  const RF177_SYSTEM_ROW = "__rezeptfinder_deleted_keys__";
  let rf177UploadRunning = false;
  let rf177DownloadRunning = false;
  let rf177ButtonToken = false;

  function rf177Status(text, error) {
    try {
      if (typeof cloudStatus === "function") cloudStatus(text, !!error);
      else console.log(text);
    } catch (e) {
      console.log(text);
    }
  }

  function rf177Id() {
    try {
      if (crypto && crypto.randomUUID) return crypto.randomUUID();
    } catch (e) {}
    return "rezept_" + Date.now() + "_" + Math.random().toString(16).slice(2);
  }

  function rf177IsSystemOrDeleted(r) {
    return !!(
      !r ||
      r.id === RF177_SYSTEM_ROW ||
      r.__system === "deleted_keys" ||
      r.system_typ === "deleted_keys" ||
      r.geloescht ||
      r.deleted ||
      r.__deleted
    );
  }

  function rf177LocalRecipes() {
    let local = [];
    try {
      local = JSON.parse(localStorage.getItem("rezepte") || "[]");
    } catch (e) {
      local = [];
    }

    // localStorage ist hier die Quelle der Wahrheit, weil Rezept speichern lokal schreibt.
    local = (Array.isArray(local) ? local : [])
      .filter(r => !rf177IsSystemOrDeleted(r))
      .map(r => {
        if (!r.id) r.id = rf177Id();
        return r;
      });

    rezepte = local;
    localStorage.setItem("rezepte", JSON.stringify(rezepte));
    return rezepte;
  }

  async function rf177Client() {
    try {
      if (typeof cloudInit === "function") cloudInit();
    } catch (e) {}

    const client = typeof supabaseClient !== "undefined" ? supabaseClient : null;
    if (!client) throw new Error("Supabase ist nicht verbunden.");
    return client;
  }

  async function rf177AllCloudRows(client) {
    const { data, error } = await client
      .from("rezepte")
      .select("id, name, daten, aktualisiert_am");

    if (error) throw error;
    return data || [];
  }

  async function rf177DeleteCloudRows(client) {
    const rows = await rf177AllCloudRows(client);
    const ids = rows
      .map(r => r.id)
      .filter(id => id && id !== RF177_SYSTEM_ROW);

    for (const id of ids) {
      try {
        await client.from("rezepte").delete().eq("id", id);
      } catch (e) {
        console.warn("Cloud-Zeile konnte nicht gelöscht werden:", id, e);
      }
    }

    return ids.length;
  }

  async function rf177DoCloudUpload() {
    if (rf177UploadRunning) {
      rf177Status("Cloud-Upload läuft bereits ...");
      return false;
    }

    rf177UploadRunning = true;

    try {
      const client = await rf177Client();
      const current = rf177LocalRecipes();

      rf177Status("ersetze Cloud ...");

      const removed = await rf177DeleteCloudRows(client);

      const rows = current.map(r => ({
        id: String(r.id),
        name: r.name || "Unbenanntes Rezept",
        daten: JSON.parse(JSON.stringify(r)),
        aktualisiert_am: new Date().toISOString()
      }));

      if (rows.length) {
        const { error } = await client
          .from("rezepte")
          .upsert(rows, { onConflict: "id" });

        if (error) throw error;
      }

      rf177Status(`${rows.length} Rezept(e) in Cloud gespeichert. Alte Cloud-Einträge entfernt: ${removed}`);
      return true;
    } catch (e) {
      console.error("Cloud-Upload v1.77 fehlgeschlagen:", e);
      rf177Status("Cloud-Upload fehlgeschlagen: " + (e.message || "unbekannter Fehler"), true);
      alert("Cloud-Upload fehlgeschlagen: " + (e.message || "unbekannter Fehler"));
      return false;
    } finally {
      // bewusst länger gesperrt, damit alte verzögerte Auto-Aufrufe nicht direkt wieder starten
      setTimeout(() => {
        rf177UploadRunning = false;
      }, 4000);
    }
  }

  async function rf177DoCloudDownload() {
    if (rf177DownloadRunning) {
      rf177Status("Cloud-Download läuft bereits ...");
      return false;
    }

    rf177DownloadRunning = true;

    try {
      const client = await rf177Client();
      rf177Status("lade aus Cloud ...");

      const { data, error } = await client
        .from("rezepte")
        .select("id, name, daten, aktualisiert_am")
        .order("aktualisiert_am", { ascending: false });

      if (error) throw error;

      rezepte = (data || [])
        .map(row => {
          const r = row.daten || {};
          if (!r.id) r.id = row.id;
          return r;
        })
        .filter(r => !rf177IsSystemOrDeleted(r));

      localStorage.setItem("rezepte", JSON.stringify(rezepte));

      try { if (typeof dashboardAktualisieren === "function") dashboardAktualisieren(); } catch (e) {}
      try { if (typeof rezeptSucheAusfuehren === "function") rezeptSucheAusfuehren(); } catch (e) {}

      rf177Status(`${rezepte.length} Rezept(e) aus Cloud geladen`);
      return true;
    } catch (e) {
      console.error("Cloud-Download v1.77 fehlgeschlagen:", e);
      rf177Status("Cloud-Download fehlgeschlagen: " + (e.message || "unbekannter Fehler"), true);
      alert("Cloud-Download fehlgeschlagen: " + (e.message || "unbekannter Fehler"));
      return false;
    } finally {
      setTimeout(() => {
        rf177DownloadRunning = false;
      }, 1500);
    }
  }

  // Nur diese beiden Funktionen werden von den echten Buttons aufgerufen.
  window.rf177CloudSaveButton = function () {
    rf177ButtonToken = true;
    try {
      return rf177DoCloudUpload();
    } finally {
      setTimeout(() => { rf177ButtonToken = false; }, 100);
    }
  };

  window.rf177CloudLoadButton = function () {
    return rf177DoCloudDownload();
  };

  // Alte automatische Upload-Aufrufe blockieren.
  function cloudSpeichernAlle() {
    if (!rf177ButtonToken) {
      console.warn("Automatischer Cloud-Upload blockiert. Bitte den Button 'Jetzt in Cloud speichern' verwenden.");
      rf177Status("Automatischer Cloud-Upload blockiert.");
      return false;
    }
    return rf177DoCloudUpload();
  }

  function cloudSpeichernAlleDirekt() { return cloudSpeichernAlle(); }
  function cloudSpeichernAlleDirekt1294() { return cloudSpeichernAlle(); }

  // Laden darf weiterhin über alte Namen funktionieren, aber ist gegen Doppellauf gesperrt.
  function cloudLaden() { return rf177DoCloudDownload(); }
  function cloudHerunterladen() { return rf177DoCloudDownload(); }
  function ausCloudLaden() { return rf177DoCloudDownload(); }

  window.cloudSpeichernAlle = cloudSpeichernAlle;
  window.cloudSpeichernAlleDirekt = cloudSpeichernAlleDirekt;
  window.cloudSpeichernAlleDirekt1294 = cloudSpeichernAlleDirekt1294;

  window.cloudLaden = cloudLaden;
  window.cloudHerunterladen = cloudHerunterladen;
  window.ausCloudLaden = ausCloudLaden;

  function rf177BindButtons() {
    document.querySelectorAll("button").forEach(btn => {
      const text = (btn.textContent || "").trim().toLowerCase();

      if (text.includes("cloud") && text.includes("speichern")) {
        btn.type = "button";
        btn.onclick = function (event) {
          if (event) {
            event.preventDefault();
            event.stopPropagation();
          }
          window.rf177CloudSaveButton();
          return false;
        };
      }

      if (text.includes("cloud") && (text.includes("laden") || text.includes("herunter"))) {
        btn.type = "button";
        btn.onclick = function (event) {
          if (event) {
            event.preventDefault();
            event.stopPropagation();
          }
          window.rf177CloudLoadButton();
          return false;
        };
      }
    });
  }

  window.addEventListener("load", function () {
    rf177BindButtons();
    setTimeout(rf177BindButtons, 500);
    setTimeout(rf177BindButtons, 1500);
  });
})();



// =====================================================
// VERSION 1.78: Bearbeiten löscht Rezept nicht mehr
// Fix:
// - Beim Bearbeiten wird die echte Rezept-ID im Formular gespeichert.
// - Beim Speichern wird zuerst nach dieser ID gesucht.
// - Wenn ID nicht gefunden wird, wird NICHT gelöscht, sondern sicher neu angelegt.
// - Bearbeiten aktualisiert genau dieses Rezept; Anzahl bleibt gleich.
// =====================================================

(function () {
  const RF178_EDIT_ID_KEY = "rf178BearbeitenId";
  const RF178_SYSTEM_ROW = "__rezeptfinder_deleted_keys__";

  function rf178Id() {
    try {
      if (crypto && crypto.randomUUID) return crypto.randomUUID();
    } catch (e) {}
    return "rezept_" + Date.now() + "_" + Math.random().toString(16).slice(2);
  }

  function rf178Text(id) {
    const el = document.getElementById(id);
    return el ? String(el.value || "").trim() : "";
  }

  function rf178NumText(v) {
    const raw = String(v || "").trim();
    if (!raw) return "";
    const n = Number(raw.replace(",", "."));
    return Number.isFinite(n) ? n : raw;
  }

  function rf178Tags(raw) {
    return String(raw || "")
      .split(/[,;#]/)
      .map(x => x.trim().toLowerCase())
      .filter(Boolean)
      .filter((x, i, arr) => arr.indexOf(x) === i);
  }

  function rf178Utensilien(raw) {
    return String(raw || "")
      .split(/[,;\n]/)
      .map(x => x.trim())
      .filter(Boolean);
  }

  function rf178DeletedKeys() {
    try { return JSON.parse(localStorage.getItem("geloeschteRezeptKeys") || "[]"); }
    catch(e) { return []; }
  }

  function rf178RecipeKeys(r) {
    if (!r) return [];
    const out = [];
    if (r.id) {
      out.push(String(r.id));
      out.push("id:" + String(r.id));
    }
    if (r.name) {
      out.push("name:" + String(r.name).trim().toLowerCase() + "|quelle:" + String(r.quelle || "").trim().toLowerCase());
    }
    return out;
  }

  function rf178IsDeletedOrSystem(r) {
    if (!r) return true;
    if (r.id === RF178_SYSTEM_ROW || r.__system === "deleted_keys" || r.system_typ === "deleted_keys") return true;
    if (r.geloescht || r.deleted || r.__deleted) return true;

    const del = new Set(rf178DeletedKeys().map(String));
    return rf178RecipeKeys(r).some(k => del.has(String(k)));
  }

  function rf178LoadLocal() {
    let local = [];
    try {
      local = JSON.parse(localStorage.getItem("rezepte") || "[]");
    } catch (e) {
      local = [];
    }

    // localStorage ist Quelle. Nicht die alte Arbeitsspeicherliste bevorzugen.
    rezepte = (Array.isArray(local) ? local : [])
      .filter(r => !rf178IsDeletedOrSystem(r))
      .map(r => {
        if (!r.id) r.id = rf178Id();
        return r;
      });

    localStorage.setItem("rezepte", JSON.stringify(rezepte));
    return rezepte;
  }

  function rf178SaveLocal(list) {
    rezepte = (Array.isArray(list) ? list : [])
      .filter(r => !rf178IsDeletedOrSystem(r))
      .map(r => {
        if (!r.id) r.id = rf178Id();
        return r;
      });

    localStorage.setItem("rezepte", JSON.stringify(rezepte));
    return rezepte;
  }

  function rf178GetEditId() {
    const hidden = document.getElementById(RF178_EDIT_ID_KEY);
    return hidden ? String(hidden.value || "").trim() : "";
  }

  function rf178SetEditId(id) {
    let hidden = document.getElementById(RF178_EDIT_ID_KEY);
    if (!hidden) {
      hidden = document.createElement("input");
      hidden.type = "hidden";
      hidden.id = RF178_EDIT_ID_KEY;
      document.body.appendChild(hidden);
    }
    hidden.value = id || "";
  }

  function rf178ClearEditId() {
    rf178SetEditId("");
    try { bearbeitungsIndex = null; } catch(e) {}
  }

  function rf178FindIndexById(id) {
    const raw = String(id || "");
    if (!raw) return -1;
    return (Array.isArray(rezepte) ? rezepte : []).findIndex(r => String(r.id || "") === raw);
  }

  function rf178EnsureRecipeIdAtIndex(index) {
    rf178LoadLocal();

    const i = Number(index);
    if (!Number.isInteger(i) || i < 0 || i >= rezepte.length || !rezepte[i]) {
      rf178ClearEditId();
      return "";
    }

    if (!rezepte[i].id) rezepte[i].id = rf178Id();
    localStorage.setItem("rezepte", JSON.stringify(rezepte));
    rf178SetEditId(rezepte[i].id);
    return rezepte[i].id;
  }

  function rf178ReadIngredients() {
    const container = document.getElementById("zutatenGruppen");
    if (!container) return [];

    const groups = [];
    Array.from(container.querySelectorAll(".zutatengruppe")).forEach((gruppe, gi) => {
      const groupEl = gruppe.querySelector(".zutaten-gruppenname");
      const groupName = groupEl && groupEl.value.trim() ? groupEl.value.trim() : (gi === 0 ? "Zutaten" : "Gruppe " + (gi + 1));
      const zutaten = [];

      Array.from(gruppe.querySelectorAll(".zutaten-zeile")).forEach(row => {
        const mengeEl = row.querySelector(".zutat-menge");
        const einheitEl = row.querySelector(".zutat-einheit");
        const nameEl = row.querySelector(".zutat-name");

        const menge = mengeEl ? String(mengeEl.value || "").trim() : "";
        const einheit = einheitEl ? String(einheitEl.value || "").trim() : "";
        const name = nameEl ? String(nameEl.value || "").trim() : "";

        if (menge || einheit || name) zutaten.push({ menge, einheit, name });
      });

      if (zutaten.length) groups.push({ name: groupName, zutaten });
    });

    return groups;
  }

  function rf178RecipeFromForm(existing) {
    const groups = rf178ReadIngredients();
    const zutaten = groups.flatMap(g => g.zutaten || []);

    return {
      id: existing && existing.id ? existing.id : (rf178GetEditId() || rf178Id()),
      name: rf178Text("nameInput"),
      kategorie: rf178Text("kategorieInput") || "Nicht zugeordnet",
      portionen: rf178NumText(rf178Text("portionenInput")),
      schwierigkeit: rf178Text("schwierigkeitInput"),
      zubereitungszeit: rf178Text("zubereitungszeitInput"),
      quelle: rf178Text("quelleInput") || "Nicht zugeordnet",
      tags: rf178Tags(rf178Text("tagsInput")),
      zubereitung: rf178Text("zubereitungInput"),
      utensilien: rf178Utensilien(rf178Text("utensilienInput")),
      notizen: rf178Text("notizenInput"),
      naehrwerte: {
        kalorien: rf178NumText(rf178Text("kalorienInput")),
        eiweiss: rf178NumText(rf178Text("eiweissInput")),
        kohlenhydrate: rf178NumText(rf178Text("kohlenhydrateInput")),
        fett: rf178NumText(rf178Text("fettInput")),
        zucker: rf178NumText(rf178Text("zuckerInput")),
        ballaststoffe: rf178NumText(rf178Text("ballaststoffeInput")),
        salz: rf178NumText(rf178Text("salzInput"))
      },
      zutatenGruppen: groups,
      zutaten,
      ausprobiert: document.getElementById("ausprobiertInput") ? document.getElementById("ausprobiertInput").value === "true" : false,
      favorit: existing ? !!existing.favorit : false,
      bewertung: existing ? Number(existing.bewertung || 0) : 0,
      erstelltAm: existing && existing.erstelltAm ? existing.erstelltAm : new Date().toISOString(),
      aktualisiertAm: new Date().toISOString()
    };
  }

  function rf178Validate(r) {
    if (!r.name) return "Bitte einen Rezeptnamen eingeben.";
    if (!r.zutaten || !r.zutaten.length) return "Bitte mindestens eine Zutat eingeben.";
    if (!r.zubereitung) return "Bitte eine Zubereitung eingeben.";
    return "";
  }

  function rf178Refresh() {
    try { if (typeof dashboardAktualisieren === "function") dashboardAktualisieren(); } catch(e) {}
    try { if (typeof suchTagsDropdownAktualisieren === "function") suchTagsDropdownAktualisieren(); } catch(e) {}
    try { if (typeof quellenDropdownAktualisieren === "function") quellenDropdownAktualisieren(); } catch(e) {}
    try { if (typeof rezeptSucheAusfuehren === "function") { rezeptSucheAusfuehren(); return; } } catch(e) {}
    try { if (typeof zeigeErgebnisse === "function") zeigeErgebnisse(rezepte.map((r, index) => ({ ...r, index }))); } catch(e) {}
  }

  function rf178LocalSaveRecipe() {
    try {
      rf178LoadLocal();

      const editId = rf178GetEditId();
      const editIndex = editId ? rf178FindIndexById(editId) : -1;
      const existing = editIndex >= 0 ? rezepte[editIndex] : null;
      const recipe = rf178RecipeFromForm(existing);
      const err = rf178Validate(recipe);

      if (err) {
        alert(err);
        return false;
      }

      if (editId && editIndex >= 0) {
        // Sicheres Bearbeiten: Anzahl bleibt gleich.
        rezepte[editIndex] = recipe;
      } else if (editId && editIndex < 0) {
        // ID ging verloren: NICHT löschen. Sicher neu anhängen.
        console.warn("Bearbeitetes Rezept wurde nicht gefunden; wird als neues Rezept gespeichert.");
        rezepte.push(recipe);
      } else {
        // Neues Rezept
        rezepte.push(recipe);
      }

      rf178ClearEditId();
      rf178SaveLocal(rezepte);
      rf178Refresh();

      if (typeof meldungAnzeigen === "function") {
        meldungAnzeigen(`Rezept gespeichert. Gesamt: ${rezepte.length}`);
      } else {
        alert(`Rezept gespeichert. Gesamt: ${rezepte.length}`);
      }

      try {
        const form = document.getElementById("formularBereich");
        if (form && form.classList) form.classList.add("versteckt");
        window.scrollTo({ top: 0, behavior: "smooth" });
      } catch(e) {}

      return true;
    } catch(e) {
      console.error("Speichern v1.78 fehlgeschlagen:", e);
      alert("Rezept konnte nicht gespeichert werden: " + (e.message || "unbekannter Fehler"));
      return false;
    }
  }

  // Bearbeiten-Button: echte ID merken, dann vorhandene Formular-Befüllung laufen lassen.
  const oldEdit178 = typeof rezeptBearbeiten === "function" ? rezeptBearbeiten : null;
  if (oldEdit178) {
    rezeptBearbeiten = function(index) {
      rf178EnsureRecipeIdAtIndex(index);
      return oldEdit178(index);
    };
    window.rezeptBearbeiten = rezeptBearbeiten;
  }

  const oldClear178 = typeof formularLeeren === "function" ? formularLeeren : null;
  if (oldClear178) {
    formularLeeren = function() {
      rf178ClearEditId();
      return oldClear178();
    };
    window.formularLeeren = formularLeeren;
  }

  const oldToggle178 = typeof rezeptHinzufuegenToggle === "function" ? rezeptHinzufuegenToggle : null;
  if (oldToggle178) {
    rezeptHinzufuegenToggle = function() {
      rf178ClearEditId();
      return oldToggle178();
    };
    window.rezeptHinzufuegenToggle = rezeptHinzufuegenToggle;
  }

  // Speichern-Funktionen überschreiben. Cloud bleibt getrennt.
  function rf155RezeptSpeichern() { return rf178LocalSaveRecipe(); }
  function rezeptSpeichernDirektCloud() { return rf178LocalSaveRecipe(); }
  function rezeptSpeichern() { return rf178LocalSaveRecipe(); }

  window.rf178LocalSaveRecipe = rf178LocalSaveRecipe;
  window.rf155RezeptSpeichern = rf178LocalSaveRecipe;
  window.rezeptSpeichernDirektCloud = rf178LocalSaveRecipe;
  window.rezeptSpeichern = rf178LocalSaveRecipe;

  function rf178BindSaveButtons() {
    document.querySelectorAll("button").forEach(btn => {
      const text = (btn.textContent || "").trim().toLowerCase();
      if (text === "rezept speichern" || text === "speichern") {
        btn.type = "button";
        btn.onclick = function(event) {
          if (event) {
            event.preventDefault();
            event.stopPropagation();
          }
          rf178LocalSaveRecipe();
          return false;
        };
      }
    });
  }

  window.addEventListener("load", function() {
    rf178LoadLocal();
    rf178BindSaveButtons();
    setTimeout(rf178BindSaveButtons, 500);
    setTimeout(rf178BindSaveButtons, 1500);
  });
})();



// =====================================================
// VERSION 1.79: Bearbeiten darf nie mehr als Löschen erkannt werden
// Ursache: alte Löschlisten enthielten auch "name:..."-Marker.
// Beim Bearbeiten wurde ein Rezept mit gleichem Namen fälschlich herausgefiltert.
// Fix:
// - name-basierte Löschmarker werden entfernt
// - Löschen/Filtern zählt nur noch echte IDs oder Softdelete-Flags
// - Bearbeiten speichert exakt die gewählte Rezept-ID
// =====================================================

(function () {
  const RF179_EDIT_ID = "rf179BearbeitenId";
  const RF179_SYSTEM_ROW = "__rezeptfinder_deleted_keys__";

  function rf179Id() {
    try {
      if (crypto && crypto.randomUUID) return crypto.randomUUID();
    } catch (e) {}
    return "rezept_" + Date.now() + "_" + Math.random().toString(16).slice(2);
  }

  function rf179CleanDeletedKeys() {
    try {
      const old = JSON.parse(localStorage.getItem("geloeschteRezeptKeys") || "[]");
      const clean = (Array.isArray(old) ? old : [])
        .map(String)
        .filter(k => k && !k.startsWith("name:")); // DAS war der gefährliche Teil
      localStorage.setItem("geloeschteRezeptKeys", JSON.stringify([...new Set(clean)]));
      return clean;
    } catch (e) {
      localStorage.setItem("geloeschteRezeptKeys", JSON.stringify([]));
      return [];
    }
  }

  function rf179DeletedIdKeys() {
    return new Set(rf179CleanDeletedKeys().map(k => String(k).replace(/^id:/, "")));
  }

  function rf179IsSystemOrSoftDeleted(r) {
    if (!r) return true;
    if (r.id === RF179_SYSTEM_ROW || r.__system === "deleted_keys" || r.system_typ === "deleted_keys") return true;
    if (r.geloescht || r.deleted || r.__deleted) return true;

    const del = rf179DeletedIdKeys();
    if (r.id && del.has(String(r.id))) return true;
    if (r.cloud_id && del.has(String(r.cloud_id))) return true;
    if (r.uuid && del.has(String(r.uuid))) return true;

    return false;
  }

  function rf179LoadLocal() {
    let local = [];
    try {
      local = JSON.parse(localStorage.getItem("rezepte") || "[]");
    } catch (e) {
      local = [];
    }

    rezepte = (Array.isArray(local) ? local : [])
      .filter(r => !rf179IsSystemOrSoftDeleted(r))
      .map(r => {
        if (!r.id) r.id = rf179Id();
        return r;
      });

    localStorage.setItem("rezepte", JSON.stringify(rezepte));
    return rezepte;
  }

  function rf179SaveLocal(list) {
    rezepte = (Array.isArray(list) ? list : [])
      .filter(r => !rf179IsSystemOrSoftDeleted(r))
      .map(r => {
        if (!r.id) r.id = rf179Id();
        return r;
      });

    localStorage.setItem("rezepte", JSON.stringify(rezepte));
    return rezepte;
  }

  function rf179SetEditId(id) {
    let el = document.getElementById(RF179_EDIT_ID);
    if (!el) {
      el = document.createElement("input");
      el.type = "hidden";
      el.id = RF179_EDIT_ID;
      document.body.appendChild(el);
    }
    el.value = id || "";
  }

  function rf179GetEditId() {
    const el = document.getElementById(RF179_EDIT_ID);
    return el ? String(el.value || "").trim() : "";
  }

  function rf179ClearEditId() {
    rf179SetEditId("");
    try { bearbeitungsIndex = null; } catch (e) {}
  }

  function rf179Text(id) {
    const el = document.getElementById(id);
    return el ? String(el.value || "").trim() : "";
  }

  function rf179NumText(v) {
    const raw = String(v || "").trim();
    if (!raw) return "";
    const n = Number(raw.replace(",", "."));
    return Number.isFinite(n) ? n : raw;
  }

  function rf179Tags(raw) {
    return String(raw || "")
      .split(/[,;#]/)
      .map(x => x.trim().toLowerCase())
      .filter(Boolean)
      .filter((x, i, arr) => arr.indexOf(x) === i);
  }

  function rf179Utensilien(raw) {
    return String(raw || "")
      .split(/[,;\n]/)
      .map(x => x.trim())
      .filter(Boolean);
  }

  function rf179ReadIngredients() {
    const container = document.getElementById("zutatenGruppen");
    if (!container) return [];

    const groups = [];
    Array.from(container.querySelectorAll(".zutatengruppe")).forEach((gruppe, gi) => {
      const groupEl = gruppe.querySelector(".zutaten-gruppenname");
      const groupName = groupEl && groupEl.value.trim() ? groupEl.value.trim() : (gi === 0 ? "Zutaten" : "Gruppe " + (gi + 1));
      const zutaten = [];

      Array.from(gruppe.querySelectorAll(".zutaten-zeile")).forEach(row => {
        const mengeEl = row.querySelector(".zutat-menge");
        const einheitEl = row.querySelector(".zutat-einheit");
        const nameEl = row.querySelector(".zutat-name");

        const menge = mengeEl ? String(mengeEl.value || "").trim() : "";
        const einheit = einheitEl ? String(einheitEl.value || "").trim() : "";
        const name = nameEl ? String(nameEl.value || "").trim() : "";

        if (menge || einheit || name) zutaten.push({ menge, einheit, name });
      });

      if (zutaten.length) groups.push({ name: groupName, zutaten });
    });

    return groups;
  }

  function rf179RecipeFromForm(existing) {
    const groups = rf179ReadIngredients();
    const zutaten = groups.flatMap(g => g.zutaten || []);

    return {
      id: existing && existing.id ? existing.id : (rf179GetEditId() || rf179Id()),
      name: rf179Text("nameInput"),
      kategorie: rf179Text("kategorieInput") || "Nicht zugeordnet",
      portionen: rf179NumText(rf179Text("portionenInput")),
      schwierigkeit: rf179Text("schwierigkeitInput"),
      zubereitungszeit: rf179Text("zubereitungszeitInput"),
      quelle: rf179Text("quelleInput") || "Nicht zugeordnet",
      tags: rf179Tags(rf179Text("tagsInput")),
      zubereitung: rf179Text("zubereitungInput"),
      utensilien: rf179Utensilien(rf179Text("utensilienInput")),
      notizen: rf179Text("notizenInput"),
      naehrwerte: {
        kalorien: rf179NumText(rf179Text("kalorienInput")),
        eiweiss: rf179NumText(rf179Text("eiweissInput")),
        kohlenhydrate: rf179NumText(rf179Text("kohlenhydrateInput")),
        fett: rf179NumText(rf179Text("fettInput")),
        zucker: rf179NumText(rf179Text("zuckerInput")),
        ballaststoffe: rf179NumText(rf179Text("ballaststoffeInput")),
        salz: rf179NumText(rf179Text("salzInput"))
      },
      zutatenGruppen: groups,
      zutaten,
      ausprobiert: document.getElementById("ausprobiertInput") ? document.getElementById("ausprobiertInput").value === "true" : false,
      favorit: existing ? !!existing.favorit : false,
      bewertung: existing ? Number(existing.bewertung || 0) : 0,
      erstelltAm: existing && existing.erstelltAm ? existing.erstelltAm : new Date().toISOString(),
      aktualisiertAm: new Date().toISOString()
    };
  }

  function rf179Validate(r) {
    if (!r.name) return "Bitte einen Rezeptnamen eingeben.";
    if (!r.zutaten || !r.zutaten.length) return "Bitte mindestens eine Zutat eingeben.";
    if (!r.zubereitung) return "Bitte eine Zubereitung eingeben.";
    return "";
  }

  function rf179FindIndexById(id) {
    const raw = String(id || "");
    if (!raw) return -1;
    return (Array.isArray(rezepte) ? rezepte : []).findIndex(r => String(r.id || "") === raw);
  }

  function rf179Refresh() {
    try { if (typeof dashboardAktualisieren === "function") dashboardAktualisieren(); } catch(e) {}
    try { if (typeof suchTagsDropdownAktualisieren === "function") suchTagsDropdownAktualisieren(); } catch(e) {}
    try { if (typeof quellenDropdownAktualisieren === "function") quellenDropdownAktualisieren(); } catch(e) {}
    try { if (typeof rezeptSucheAusfuehren === "function") { rezeptSucheAusfuehren(); return; } } catch(e) {}
    try { if (typeof zeigeErgebnisse === "function") zeigeErgebnisse(rezepte.map((r, index) => ({ ...r, index }))); } catch(e) {}
  }

  function rf179LocalSaveRecipe() {
    try {
      rf179CleanDeletedKeys();
      rf179LoadLocal();

      const editId = rf179GetEditId();
      const editIndex = editId ? rf179FindIndexById(editId) : -1;
      const existing = editIndex >= 0 ? rezepte[editIndex] : null;
      const recipe = rf179RecipeFromForm(existing);
      const err = rf179Validate(recipe);

      if (err) {
        alert(err);
        return false;
      }

      if (editId && editIndex >= 0) {
        rezepte[editIndex] = recipe;          // Bearbeiten: Anzahl bleibt gleich
      } else if (editId && editIndex < 0) {
        rezepte.push(recipe);                 // Sicherheitsfall: nicht löschen
      } else {
        rezepte.push(recipe);                 // Neu
      }

      rf179ClearEditId();
      rf179SaveLocal(rezepte);
      rf179Refresh();

      if (typeof meldungAnzeigen === "function") {
        meldungAnzeigen(`Rezept gespeichert. Gesamt: ${rezepte.length}`);
      } else {
        alert(`Rezept gespeichert. Gesamt: ${rezepte.length}`);
      }

      try {
        const form = document.getElementById("formularBereich");
        if (form && form.classList) form.classList.add("versteckt");
        window.scrollTo({ top: 0, behavior: "smooth" });
      } catch(e) {}

      return true;
    } catch(e) {
      console.error("Speichern v1.79 fehlgeschlagen:", e);
      alert("Rezept konnte nicht gespeichert werden: " + (e.message || "unbekannter Fehler"));
      return false;
    }
  }

  const oldEdit179 = typeof rezeptBearbeiten === "function" ? rezeptBearbeiten : null;
  if (oldEdit179) {
    rezeptBearbeiten = function(index) {
      rf179CleanDeletedKeys();
      rf179LoadLocal();

      const i = Number(index);
      if (Number.isInteger(i) && rezepte[i]) {
        if (!rezepte[i].id) rezepte[i].id = rf179Id();
        localStorage.setItem("rezepte", JSON.stringify(rezepte));
        rf179SetEditId(rezepte[i].id);
      } else {
        rf179ClearEditId();
      }

      return oldEdit179(index);
    };
    window.rezeptBearbeiten = rezeptBearbeiten;
  }

  const oldClear179 = typeof formularLeeren === "function" ? formularLeeren : null;
  if (oldClear179) {
    formularLeeren = function() {
      rf179ClearEditId();
      return oldClear179();
    };
    window.formularLeeren = formularLeeren;
  }

  const oldToggle179 = typeof rezeptHinzufuegenToggle === "function" ? rezeptHinzufuegenToggle : null;
  if (oldToggle179) {
    rezeptHinzufuegenToggle = function() {
      rf179ClearEditId();
      return oldToggle179();
    };
    window.rezeptHinzufuegenToggle = rezeptHinzufuegenToggle;
  }

  function rf155RezeptSpeichern() { return rf179LocalSaveRecipe(); }
  function rezeptSpeichernDirektCloud() { return rf179LocalSaveRecipe(); }
  function rezeptSpeichern() { return rf179LocalSaveRecipe(); }

  window.rf179LocalSaveRecipe = rf179LocalSaveRecipe;
  window.rf155RezeptSpeichern = rf179LocalSaveRecipe;
  window.rezeptSpeichernDirektCloud = rf179LocalSaveRecipe;
  window.rezeptSpeichern = rf179LocalSaveRecipe;

  function rf179BindSaveButtons() {
    document.querySelectorAll("button").forEach(btn => {
      const text = (btn.textContent || "").trim().toLowerCase();
      if (text === "rezept speichern" || text === "speichern") {
        btn.type = "button";
        btn.onclick = function(event) {
          if (event) {
            event.preventDefault();
            event.stopPropagation();
          }
          rf179LocalSaveRecipe();
          return false;
        };
      }
    });
  }

  window.addEventListener("load", function() {
    rf179CleanDeletedKeys();
    rf179LoadLocal();
    rf179BindSaveButtons();
    setTimeout(rf179BindSaveButtons, 500);
    setTimeout(rf179BindSaveButtons, 1500);
  });
})();



// =====================================================
// VERSION 1.80 TIMER FIX
// Küchentimer wiederhergestellt
// =====================================================

(function () {
  let rf180TimerInterval = null;
  let rf180TimerRest = 0;

  function rf180Format(sec) {
    const m = Math.floor(sec / 60);
    const s = sec % 60;
    return String(m).padStart(2, "0") + ":" + String(s).padStart(2, "0");
  }

  function rf180Update() {
    const el = document.getElementById("kochTimerAnzeige");
    if (el) el.textContent = rf180Format(rf180TimerRest);
  }

  function rf180PlayAlarm() {
    try {
      const audio = new Audio("data:audio/wav;base64,UklGRl9vT19XQVZFZm10IBAAAAABAAEAESsAACJWAAACABAAZGF0YU");
      audio.play().catch(()=>{});
    } catch(e){}
  }

  window.rf180TimerStart = function(seconds) {
    rf180TimerStop();
    rf180TimerRest = Number(seconds) || 0;
    rf180Update();

    rf180TimerInterval = setInterval(() => {
      rf180TimerRest--;

      if (rf180TimerRest <= 0) {
        rf180TimerRest = 0;
        rf180Update();
        rf180TimerStop();
        rf180PlayAlarm();
        alert("Timer beendet!");
        return;
      }

      rf180Update();
    }, 1000);
  };

  window.rf180TimerStop = function() {
    if (rf180TimerInterval) {
      clearInterval(rf180TimerInterval);
      rf180TimerInterval = null;
    }
  };

  window.addEventListener("load", function () {
    rf180Update();
  });
})();



// =====================================================
// VERSION 1.81 Einkaufsliste Format-Fix
// Normalisiert vorhandene Einkaufsliste-Einträge in ein sauberes Layout.
// =====================================================

(function () {
  function rf181FormatEinkaufsliste() {
    const bereich =
      document.getElementById("einkaufslisteBereich") ||
      document.getElementById("einkaufsliste") ||
      document.querySelector(".einkaufsliste");

    if (!bereich) return;

    const kandidaten = Array.from(bereich.querySelectorAll("li, .einkaufsliste-item, .einkaufslisten-item, .shopping-item"));

    kandidaten.forEach(item => {
      if (item.dataset.rf181Formatted === "1") return;

      const checkbox = item.querySelector('input[type="checkbox"]');
      const rawText = Array.from(item.childNodes)
        .map(n => n.nodeType === Node.TEXT_NODE ? n.textContent : "")
        .join(" ")
        .replace(/\s+/g, " ")
        .trim();

      if (!checkbox && !rawText) return;

      let text = rawText || item.textContent.replace(/\s+/g, " ").trim();
      text = text.replace(/^✓\s*/, "").trim();

      const match = text.match(/^(\d+(?:[,.]\d+)?\s*[a-zA-ZäöüÄÖÜß]+)?\s*(.*)$/);
      const menge = match && match[1] ? match[1].trim() : "";
      const name = match && match[2] ? match[2].trim() : text;

      item.classList.add("einkaufsliste-item");
      item.dataset.rf181Formatted = "1";
      item.innerHTML = "";

      const cb = checkbox || document.createElement("input");
      cb.type = "checkbox";

      const mengeEl = document.createElement("span");
      mengeEl.className = "einkaufsliste-menge";
      mengeEl.textContent = menge;

      const nameEl = document.createElement("span");
      nameEl.className = "einkaufsliste-name";
      nameEl.textContent = name || text;

      item.appendChild(cb);
      item.appendChild(mengeEl);
      item.appendChild(nameEl);
    });
  }

  const oldEinkaufRender181 =
    typeof einkaufslisteAnzeigen === "function" ? einkaufslisteAnzeigen : null;

  if (oldEinkaufRender181) {
    einkaufslisteAnzeigen = function () {
      const result = oldEinkaufRender181.apply(this, arguments);
      setTimeout(rf181FormatEinkaufsliste, 0);
      return result;
    };
    window.einkaufslisteAnzeigen = einkaufslisteAnzeigen;
  }

  const oldEinkaufToggle181 =
    typeof einkaufslisteToggle === "function" ? einkaufslisteToggle : null;

  if (oldEinkaufToggle181) {
    einkaufslisteToggle = function () {
      const result = oldEinkaufToggle181.apply(this, arguments);
      setTimeout(rf181FormatEinkaufsliste, 0);
      setTimeout(rf181FormatEinkaufsliste, 300);
      return result;
    };
    window.einkaufslisteToggle = einkaufslisteToggle;
  }

  window.rf181FormatEinkaufsliste = rf181FormatEinkaufsliste;

  window.addEventListener("load", function () {
    rf181FormatEinkaufsliste();
    setTimeout(rf181FormatEinkaufsliste, 500);
    setTimeout(rf181FormatEinkaufsliste, 1500);
  });
})();



// =====================================================
// VERSION 1.82 Rezept-Assistent automatisch zurücksetzen
// Nach Übernahme ins Formular oder Speichern wird der Assistent geleert.
// =====================================================

(function () {
  function rf182AssistentZuruecksetzen() {
    const ids = [
      "rezeptAssistentInput",
      "assistentInput",
      "textImportInput",
      "rezeptTextInput",
      "importTextInput"
    ];

    ids.forEach(id => {
      const el = document.getElementById(id);
      if (el) el.value = "";
    });

    const previewIds = [
      "assistentVorschau",
      "rezeptAssistentVorschau",
      "analyseVorschau",
      "vorschauBereich",
      "importVorschau"
    ];

    previewIds.forEach(id => {
      const el = document.getElementById(id);
      if (el) {
        el.innerHTML = "";
        if (el.classList) el.classList.add("versteckt");
      }
    });

    try {
      window.letzteAnalyse = null;
      window.assistentAnalyse = null;
      window.rfAnalyseErgebnis = null;
    } catch (e) {}
  }

  window.rf182AssistentZuruecksetzen = rf182AssistentZuruecksetzen;

  const alteUebernahme182 =
    typeof assistentInsFormularUebernehmen === "function"
      ? assistentInsFormularUebernehmen
      : null;

  if (alteUebernahme182) {
    assistentInsFormularUebernehmen = function () {
      const result = alteUebernahme182.apply(this, arguments);
      setTimeout(rf182AssistentZuruecksetzen, 100);
      return result;
    };
    window.assistentInsFormularUebernehmen = assistentInsFormularUebernehmen;
  }

  const alteImportUebernahme182 =
    typeof rezeptAusAnalyseInsFormular === "function"
      ? rezeptAusAnalyseInsFormular
      : null;

  if (alteImportUebernahme182) {
    rezeptAusAnalyseInsFormular = function () {
      const result = alteImportUebernahme182.apply(this, arguments);
      setTimeout(rf182AssistentZuruecksetzen, 100);
      return result;
    };
    window.rezeptAusAnalyseInsFormular = rezeptAusAnalyseInsFormular;
  }

  const alteSpeichern182 =
    typeof rezeptSpeichernDirektCloud === "function"
      ? rezeptSpeichernDirektCloud
      : null;

  if (alteSpeichern182) {
    rezeptSpeichernDirektCloud = function () {
      const result = alteSpeichern182.apply(this, arguments);
      setTimeout(rf182AssistentZuruecksetzen, 100);
      return result;
    };
    window.rezeptSpeichernDirektCloud = rezeptSpeichernDirektCloud;
  }

  const alteSpeichernFenster182 =
    typeof rezeptSpeichern === "function"
      ? rezeptSpeichern
      : null;

  if (alteSpeichernFenster182) {
    rezeptSpeichern = function () {
      const result = alteSpeichernFenster182.apply(this, arguments);
      setTimeout(rf182AssistentZuruecksetzen, 100);
      return result;
    };
    window.rezeptSpeichern = rezeptSpeichern;
  }

  function rf182ButtonsNachbinden() {
    document.querySelectorAll("button").forEach(button => {
      const text = (button.textContent || "").trim().toLowerCase();

      if (
        text.includes("ins formular") ||
        text.includes("übernehmen") ||
        text.includes("uebernehmen")
      ) {
        if (button.dataset.rf182Bound === "1") return;
        button.dataset.rf182Bound = "1";

        const oldClick = button.onclick;
        button.onclick = function (event) {
          const result = oldClick ? oldClick.call(this, event) : true;
          setTimeout(rf182AssistentZuruecksetzen, 150);
          return result;
        };
      }
    });
  }

  window.addEventListener("load", function () {
    rf182ButtonsNachbinden();
    setTimeout(rf182ButtonsNachbinden, 500);
    setTimeout(rf182ButtonsNachbinden, 1500);
  });
})();



// =====================================================
// VERSION 1.83 Doppelte Zutaten zusammenführen repariert
// =====================================================

(function () {
  function rf183NormName(name) {
    return String(name || "")
      .trim()
      .toLowerCase()
      .replace(/\s+/g, " ");
  }

  function rf183NormEinheit(einheit) {
    return String(einheit || "")
      .trim()
      .toLowerCase()
      .replace(/\s+/g, " ");
  }

  function rf183ParseMenge(value) {
    const raw = String(value || "").trim().replace(",", ".");
    if (!raw) return { zahl: 0, istZahl: true };

    const n = Number(raw);
    if (Number.isFinite(n)) return { zahl: n, istZahl: true };

    return { text: String(value || "").trim(), istZahl: false };
  }

  function rf183FormatZahl(n) {
    if (!Number.isFinite(n)) return "";
    const rounded = Math.round(n * 1000) / 1000;
    return String(rounded).replace(".", ",");
  }

  function rf183ZutatenRows() {
    const container = document.getElementById("zutatenGruppen");
    if (!container) return [];

    return Array.from(container.querySelectorAll(".zutaten-zeile")).map(row => ({
      row,
      mengeEl: row.querySelector(".zutat-menge"),
      einheitEl: row.querySelector(".zutat-einheit"),
      nameEl: row.querySelector(".zutat-name")
    })).filter(x => x.nameEl);
  }

  function rf183DoppelteZutatenZusammenfuehren() {
    const rows = rf183ZutatenRows();

    if (!rows.length) {
      alert("Keine Zutaten gefunden.");
      return false;
    }

    const map = new Map();
    const removeRows = [];

    rows.forEach(item => {
      const name = item.nameEl ? item.nameEl.value.trim() : "";
      const einheit = item.einheitEl ? item.einheitEl.value.trim() : "";
      const menge = item.mengeEl ? item.mengeEl.value.trim() : "";

      if (!name) return;

      const key = rf183NormName(name) + "||" + rf183NormEinheit(einheit);

      if (!map.has(key)) {
        map.set(key, {
          first: item,
          name,
          einheit,
          menge,
          summe: rf183ParseMenge(menge),
          texte: []
        });
        return;
      }

      const current = map.get(key);
      const parsed = rf183ParseMenge(menge);

      if (current.summe.istZahl && parsed.istZahl) {
        current.summe.zahl += parsed.zahl;
        if (current.first.mengeEl) current.first.mengeEl.value = rf183FormatZahl(current.summe.zahl);
      } else {
        const values = [current.first.mengeEl ? current.first.mengeEl.value.trim() : "", menge]
          .filter(Boolean);
        if (current.first.mengeEl) current.first.mengeEl.value = values.join(" + ");
        current.summe.istZahl = false;
      }

      removeRows.push(item.row);
    });

    removeRows.forEach(row => row.remove());

    if (!removeRows.length) {
      alert("Keine doppelten Zutaten gefunden.");
    } else {
      if (typeof meldungAnzeigen === "function") {
        meldungAnzeigen(removeRows.length + " doppelte Zutat(en) zusammengeführt.");
      } else {
        alert(removeRows.length + " doppelte Zutat(en) zusammengeführt.");
      }
    }

    return true;
  }

  window.rf183DoppelteZutatenZusammenfuehren = rf183DoppelteZutatenZusammenfuehren;

  // Alle möglichen alten Namen auf neue Funktion legen.
  window.doppelteZutatenZusammenfuehren = rf183DoppelteZutatenZusammenfuehren;
  window.zutatenZusammenfuehren = rf183DoppelteZutatenZusammenfuehren;
  window.doppelteZutatenEntfernen = rf183DoppelteZutatenZusammenfuehren;

  function doppelteZutatenZusammenfuehren() {
    return rf183DoppelteZutatenZusammenfuehren();
  }

  function zutatenZusammenfuehren() {
    return rf183DoppelteZutatenZusammenfuehren();
  }

  function doppelteZutatenEntfernen() {
    return rf183DoppelteZutatenZusammenfuehren();
  }

  function rf183ButtonBinden() {
    document.querySelectorAll("button").forEach(button => {
      const text = (button.textContent || "").trim().toLowerCase();

      if (text.includes("doppelte") && text.includes("zutaten")) {
        button.type = "button";
        button.onclick = function (event) {
          if (event) {
            event.preventDefault();
            event.stopPropagation();
          }
          rf183DoppelteZutatenZusammenfuehren();
          return false;
        };
      }
    });
  }

  window.addEventListener("load", function () {
    rf183ButtonBinden();
    setTimeout(rf183ButtonBinden, 500);
    setTimeout(rf183ButtonBinden, 1500);
  });
})();


// =====================================================
// VERSION 1.84 Bearbeiten ersetzt statt dupliziert
// =====================================================

(function () {

  function rf184GetEditId() {
    const ids = [
      "rf179BearbeitenId",
      "rf178BearbeitenId",
      "rf176BearbeitenId",
      "bearbeitenId",
      "editRecipeId"
    ];

    for (const id of ids) {
      const el = document.getElementById(id);
      if (el && String(el.value || "").trim()) {
        return String(el.value || "").trim();
      }
    }

    return "";
  }

  function rf184CleanupDuplicates() {
    try {
      let arr = JSON.parse(localStorage.getItem("rezepte") || "[]");

      const seen = new Set();
      const cleaned = [];

      arr.forEach(recipe => {
        if (!recipe) return;

        const rid = String(
          recipe.id ||
          recipe.uuid ||
          recipe.cloud_id ||
          ""
        );

        if (!rid) {
          cleaned.push(recipe);
          return;
        }

        if (seen.has(rid)) {
          return;
        }

        seen.add(rid);
        cleaned.push(recipe);
      });

      localStorage.setItem("rezepte", JSON.stringify(cleaned));
      rezepte = cleaned;

      try {
        if (typeof rezeptSucheAusfuehren === "function") rezeptSucheAusfuehren();
      } catch(e) {}

      try {
        if (typeof dashboardAktualisieren === "function") dashboardAktualisieren();
      } catch(e) {}

    } catch(e) {
      console.error(e);
    }
  }

  function rf184ClearEditIds() {
    [
      "rf179BearbeitenId",
      "rf178BearbeitenId",
      "rf176BearbeitenId",
      "bearbeitenId",
      "editRecipeId"
    ].forEach(id => {
      const el = document.getElementById(id);
      if (el) el.value = "";
    });

    try { bearbeitungsIndex = null; } catch(e) {}
  }

  const oldSave184 =
    typeof rezeptSpeichern === "function"
      ? rezeptSpeichern
      : null;

  if (oldSave184) {
    rezeptSpeichern = function() {
      const editId = rf184GetEditId();
      const result = oldSave184.apply(this, arguments);

      if (editId) {
        setTimeout(() => {
          rf184CleanupDuplicates();
          rf184ClearEditIds();
        }, 150);
      }

      return result;
    };

    window.rezeptSpeichern = rezeptSpeichern;
  }

  const oldSaveCloud184 =
    typeof rezeptSpeichernDirektCloud === "function"
      ? rezeptSpeichernDirektCloud
      : null;

  if (oldSaveCloud184) {
    rezeptSpeichernDirektCloud = function() {
      const editId = rf184GetEditId();
      const result = oldSaveCloud184.apply(this, arguments);

      if (editId) {
        setTimeout(() => {
          rf184CleanupDuplicates();
          rf184ClearEditIds();
        }, 150);
      }

      return result;
    };

    window.rezeptSpeichernDirektCloud = rezeptSpeichernDirektCloud;
  }

})();



// =====================================================
// VERSION 1.85: Bearbeiten/Löschen bei Duplikaten endgültig repariert
// Problem:
// - doppelte Rezepte hatten dieselbe ID
// - Bearbeiten erzeugte zusätzliches Rezept
// - Löschen entfernte beide wegen gleicher ID
// Fix:
// - doppelte IDs werden automatisch eindeutig gemacht
// - Bearbeiten ersetzt den ursprünglichen Listenplatz
// - Löschen entfernt nur genau einen Eintrag
// =====================================================

(function () {
  let rf185EditIndex = null;
  let rf185EditId = "";

  function rf185Id() {
    try {
      if (crypto && crypto.randomUUID) return crypto.randomUUID();
    } catch (e) {}
    return "rezept_" + Date.now() + "_" + Math.random().toString(16).slice(2);
  }

  function rf185Load() {
    try {
      rezepte = JSON.parse(localStorage.getItem("rezepte") || "[]");
    } catch (e) {
      rezepte = Array.isArray(rezepte) ? rezepte : [];
    }

    if (!Array.isArray(rezepte)) rezepte = [];
    return rezepte;
  }

  function rf185Save() {
    localStorage.setItem("rezepte", JSON.stringify(rezepte));
  }

  function rf185SanitizeDuplicateIds() {
    rf185Load();

    const used = new Set();
    let changed = false;

    rezepte.forEach((r, index) => {
      if (!r) return;

      if (!r.id) {
        r.id = rf185Id();
        changed = true;
      }

      const id = String(r.id);

      if (used.has(id)) {
        // Wichtig: Duplikat bekommt eigene ID, damit Löschen nicht beide entfernt.
        r.id = rf185Id();
        r.aktualisiertAm = new Date().toISOString();
        changed = true;
      }

      used.add(String(r.id));
    });

    if (changed) rf185Save();
    return changed;
  }

  function rf185Refresh() {
    try { if (typeof dashboardAktualisieren === "function") dashboardAktualisieren(); } catch(e) {}
    try { if (typeof rezeptSucheAusfuehren === "function") { rezeptSucheAusfuehren(); return; } } catch(e) {}
    try { if (typeof zeigeErgebnisse === "function") zeigeErgebnisse(rezepte.map((r, index) => ({ ...r, index }))); } catch(e) {}
  }

  function rf185RememberEdit(index) {
    rf185SanitizeDuplicateIds();

    const i = Number(index);
    if (Number.isInteger(i) && i >= 0 && i < rezepte.length && rezepte[i]) {
      rf185EditIndex = i;
      rf185EditId = String(rezepte[i].id || "");
    } else {
      rf185EditIndex = null;
      rf185EditId = "";
    }
  }

  function rf185RepairAfterEditSave() {
    if (rf185EditIndex === null || rf185EditIndex === undefined) {
      rf185SanitizeDuplicateIds();
      return;
    }

    rf185Load();

    const originalIndex = Number(rf185EditIndex);

    if (!Number.isInteger(originalIndex) || originalIndex < 0) {
      rf185EditIndex = null;
      rf185EditId = "";
      rf185SanitizeDuplicateIds();
      return;
    }

    // Typischer Fehler: Speichern hat bearbeitetes Rezept hinten angehängt.
    // Dann nehmen wir den letzten Eintrag, setzen ihn an die ursprüngliche Stelle
    // und entfernen das angehängte Duplikat.
    if (rezepte.length > originalIndex + 1) {
      const lastIndex = rezepte.length - 1;
      const last = rezepte[lastIndex];

      if (last && lastIndex !== originalIndex) {
        last.id = rf185EditId || last.id || rf185Id();
        last.aktualisiertAm = new Date().toISOString();

        rezepte[originalIndex] = last;
        rezepte.splice(lastIndex, 1);
      }
    }

    // Falls mehrere gleiche IDs existieren, jetzt trennen.
    rf185Save();
    rf185SanitizeDuplicateIds();

    rf185EditIndex = null;
    rf185EditId = "";
    try { bearbeitungsIndex = null; } catch(e) {}

    rf185Refresh();
  }

  const oldEdit185 = typeof rezeptBearbeiten === "function" ? rezeptBearbeiten : null;
  if (oldEdit185) {
    rezeptBearbeiten = function(index) {
      rf185RememberEdit(index);
      return oldEdit185(index);
    };
    window.rezeptBearbeiten = rezeptBearbeiten;
  }

  const oldSave185 = typeof rezeptSpeichern === "function" ? rezeptSpeichern : null;
  if (oldSave185) {
    rezeptSpeichern = function() {
      const result = oldSave185.apply(this, arguments);
      setTimeout(rf185RepairAfterEditSave, 200);
      return result;
    };
    window.rezeptSpeichern = rezeptSpeichern;
  }

  const oldDirectSave185 = typeof rezeptSpeichernDirektCloud === "function" ? rezeptSpeichernDirektCloud : null;
  if (oldDirectSave185) {
    rezeptSpeichernDirektCloud = function() {
      const result = oldDirectSave185.apply(this, arguments);
      setTimeout(rf185RepairAfterEditSave, 200);
      return result;
    };
    window.rezeptSpeichernDirektCloud = rezeptSpeichernDirektCloud;
  }

  function rf185DeleteOne(indexOderId) {
    rf185SanitizeDuplicateIds();

    let i = -1;
    const raw = String(indexOderId || "");

    if (/^\d+$/.test(raw)) {
      const n = Number(raw);
      if (n >= 0 && n < rezepte.length) i = n;
    }

    if (i < 0) {
      i = rezepte.findIndex(r => r && String(r.id || "") === raw);
    }

    if (i < 0 || !rezepte[i]) {
      alert("Rezept konnte nicht gefunden werden.");
      return false;
    }

    const name = rezepte[i].name || "dieses Rezept";

    if (!confirm(`Möchtest du "${name}" wirklich löschen?`)) {
      return false;
    }

    // Genau EINEN Eintrag löschen, nicht alle mit gleicher ID.
    rezepte.splice(i, 1);
    rf185Save();
    rf185SanitizeDuplicateIds();
    rf185Refresh();

    if (typeof meldungAnzeigen === "function") {
      meldungAnzeigen(`Rezept "${name}" gelöscht.`);
    }

    return true;
  }

  window.rf185DeleteOne = rf185DeleteOne;
  window.rezeptLoeschen = rf185DeleteOne;

  // Beim Start alte doppelte IDs sofort reparieren.
  window.addEventListener("load", function() {
    rf185SanitizeDuplicateIds();
    setTimeout(rf185SanitizeDuplicateIds, 500);
  });
})();


// =====================================================
// VERSION 1.86 FINAL EDIT FIX
// Rezept bearbeiten ersetzt jetzt WIRKLICH den alten Eintrag.
// =====================================================

(function () {

  let rf186CurrentEditIndex = null;

  function rf186LoadRecipes() {
    try {
      rezepte = JSON.parse(localStorage.getItem("rezepte") || "[]");
    } catch(e) {
      rezepte = Array.isArray(rezepte) ? rezepte : [];
    }

    if (!Array.isArray(rezepte)) rezepte = [];
    return rezepte;
  }

  function rf186SaveRecipes() {
    localStorage.setItem("rezepte", JSON.stringify(rezepte));
  }

  function rf186Refresh() {
    try {
      if (typeof dashboardAktualisieren === "function") {
        dashboardAktualisieren();
      }
    } catch(e) {}

    try {
      if (typeof rezeptSucheAusfuehren === "function") {
        rezeptSucheAusfuehren();
        return;
      }
    } catch(e) {}

    try {
      if (typeof zeigeErgebnisse === "function") {
        zeigeErgebnisse(rezepte.map((r, index) => ({ ...r, index })));
      }
    } catch(e) {}
  }

  // WICHTIG:
  // Beim Bearbeiten merken wir uns NUR DEN INDEX.
  // Nicht mehr die ID.
  // Genau dort wird später ersetzt.
  const oldEdit186 =
    typeof rezeptBearbeiten === "function"
      ? rezeptBearbeiten
      : null;

  if (oldEdit186) {
    rezeptBearbeiten = function(index) {
      rf186LoadRecipes();

      const i = Number(index);

      if (
        Number.isInteger(i) &&
        i >= 0 &&
        i < rezepte.length
      ) {
        rf186CurrentEditIndex = i;
      } else {
        rf186CurrentEditIndex = null;
      }

      return oldEdit186(index);
    };

    window.rezeptBearbeiten = rezeptBearbeiten;
  }

  function rf186BuildRecipeFromForm() {

    function text(id) {
      const el = document.getElementById(id);
      return el ? String(el.value || "").trim() : "";
    }

    function tags(raw) {
      return String(raw || "")
        .split(/[,;#]/)
        .map(x => x.trim().toLowerCase())
        .filter(Boolean)
        .filter((x, i, arr) => arr.indexOf(x) === i);
    }

    function utensilien(raw) {
      return String(raw || "")
        .split(/[,;\n]/)
        .map(x => x.trim())
        .filter(Boolean);
    }

    const groups = [];
    const container = document.getElementById("zutatenGruppen");

    if (container) {
      Array.from(container.querySelectorAll(".zutatengruppe")).forEach((gruppe, gi) => {

        const groupEl = gruppe.querySelector(".zutaten-gruppenname");

        const groupName =
          groupEl && groupEl.value.trim()
            ? groupEl.value.trim()
            : (gi === 0 ? "Zutaten" : "Gruppe " + (gi + 1));

        const zutaten = [];

        Array.from(gruppe.querySelectorAll(".zutaten-zeile")).forEach(row => {

          const mengeEl = row.querySelector(".zutat-menge");
          const einheitEl = row.querySelector(".zutat-einheit");
          const nameEl = row.querySelector(".zutat-name");

          const menge = mengeEl ? String(mengeEl.value || "").trim() : "";
          const einheit = einheitEl ? String(einheitEl.value || "").trim() : "";
          const name = nameEl ? String(nameEl.value || "").trim() : "";

          if (menge || einheit || name) {
            zutaten.push({
              menge,
              einheit,
              name
            });
          }
        });

        if (zutaten.length) {
          groups.push({
            name: groupName,
            zutaten
          });
        }
      });
    }

    const flat = groups.flatMap(g => g.zutaten || []);

    let existing = null;

    if (
      rf186CurrentEditIndex !== null &&
      Array.isArray(rezepte) &&
      rezepte[rf186CurrentEditIndex]
    ) {
      existing = rezepte[rf186CurrentEditIndex];
    }

    return {
      id:
        existing && existing.id
          ? existing.id
          : ("rezept_" + Date.now() + "_" + Math.random().toString(16).slice(2)),

      name: text("nameInput"),
      kategorie: text("kategorieInput") || "Nicht zugeordnet",
      portionen: text("portionenInput"),
      schwierigkeit: text("schwierigkeitInput"),
      zubereitungszeit: text("zubereitungszeitInput"),
      quelle: text("quelleInput") || "Nicht zugeordnet",
      tags: tags(text("tagsInput")),
      zubereitung: text("zubereitungInput"),
      utensilien: utensilien(text("utensilienInput")),
      notizen: text("notizenInput"),

      naehrwerte: {
        kalorien: text("kalorienInput"),
        eiweiss: text("eiweissInput"),
        kohlenhydrate: text("kohlenhydrateInput"),
        fett: text("fettInput"),
        zucker: text("zuckerInput"),
        ballaststoffe: text("ballaststoffeInput"),
        salz: text("salzInput")
      },

      zutatenGruppen: groups,
      zutaten: flat,

      ausprobiert:
        document.getElementById("ausprobiertInput")
          ? document.getElementById("ausprobiertInput").value === "true"
          : false,

      favorit:
        existing
          ? !!existing.favorit
          : false,

      bewertung:
        existing
          ? Number(existing.bewertung || 0)
          : 0,

      erstelltAm:
        existing && existing.erstelltAm
          ? existing.erstelltAm
          : new Date().toISOString(),

      aktualisiertAm:
        new Date().toISOString()
    };
  }

  // DAS ersetzt die bisherigen kaputten Speicherlogiken.
  function rf186SaveRecipe() {

    rf186LoadRecipes();

    const recipe = rf186BuildRecipeFromForm();

    if (!recipe.name) {
      alert("Bitte einen Rezeptnamen eingeben.");
      return false;
    }

    if (!recipe.zutaten || !recipe.zutaten.length) {
      alert("Bitte mindestens eine Zutat eingeben.");
      return false;
    }

    if (!recipe.zubereitung) {
      alert("Bitte eine Zubereitung eingeben.");
      return false;
    }

    // ENTSCHEIDENDER FIX:
    // Beim Bearbeiten wird EXAKT dieser Listenplatz ersetzt.
    if (
      rf186CurrentEditIndex !== null &&
      Number.isInteger(rf186CurrentEditIndex) &&
      rf186CurrentEditIndex >= 0 &&
      rf186CurrentEditIndex < rezepte.length
    ) {
      rezepte[rf186CurrentEditIndex] = recipe;
    } else {
      rezepte.push(recipe);
    }

    // Doppelte IDs entfernen
    const seen = new Set();
    rezepte = rezepte.filter(r => {
      if (!r) return false;

      const id = String(r.id || "");

      if (!id) return true;

      if (seen.has(id)) return false;

      seen.add(id);
      return true;
    });

    rf186SaveRecipes();
    rf186Refresh();

    rf186CurrentEditIndex = null;

    try { bearbeitungsIndex = null; } catch(e) {}

    try {
      const form = document.getElementById("formularBereich");
      if (form && form.classList) {
        form.classList.add("versteckt");
      }
    } catch(e) {}

    if (typeof meldungAnzeigen === "function") {
      meldungAnzeigen("Rezept gespeichert.");
    }

    return true;
  }

  // ALLE alten Speicherfunktionen hart überschreiben
  window.rf186SaveRecipe = rf186SaveRecipe;
  window.rezeptSpeichern = rf186SaveRecipe;
  window.rezeptSpeichernDirektCloud = rf186SaveRecipe;
  window.rf155RezeptSpeichern = rf186SaveRecipe;

  function rezeptSpeichern() {
    return rf186SaveRecipe();
  }

  function rezeptSpeichernDirektCloud() {
    return rf186SaveRecipe();
  }

  function rf155RezeptSpeichern() {
    return rf186SaveRecipe();
  }

})();



// =====================================================
// VERSION 1.87 Einkaufsliste Darstellung wirklich ersetzen
// =====================================================

(function () {
  function esc187(value) {
    return String(value == null ? "" : value)
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;");
  }

  function rf187ParseItem(item) {
    if (typeof item === "string") {
      const text = item.trim();
      const m = text.match(/^(\d+(?:[,.]\d+)?\s*[a-zA-ZäöüÄÖÜß]*)\s+(.+)$/);
      return {
        menge: m ? m[1].trim() : "",
        name: m ? m[2].trim() : text,
        erledigt: false
      };
    }

    item = item || {};
    const menge = [item.menge, item.einheit].filter(Boolean).join(" ").trim();

    return {
      menge,
      name: item.name || item.zutat || item.text || "",
      erledigt: !!item.erledigt
    };
  }

  function rf187LadeEinkaufsliste() {
    const keys = ["einkaufsliste", "einkaufsListe", "shoppingList"];

    for (const key of keys) {
      try {
        const value = JSON.parse(localStorage.getItem(key) || "[]");
        if (Array.isArray(value) && value.length) return { key, liste: value };
      } catch (e) {}
    }

    return { key: "einkaufsliste", liste: [] };
  }

  function rf187SpeichereEinkaufsliste(key, liste) {
    localStorage.setItem(key || "einkaufsliste", JSON.stringify(liste));
  }

  function rf187RenderEinkaufsliste() {
    const container =
      document.getElementById("einkaufslisteInhalt") ||
      document.getElementById("einkaufslisteListe") ||
      document.getElementById("einkaufsliste") ||
      document.querySelector("#einkaufslisteBereich .inhalt") ||
      document.querySelector("#einkaufslisteBereich");

    if (!container) return false;

    const data = rf187LadeEinkaufsliste();
    const liste = data.liste;

    if (!liste.length) {
      container.innerHTML = '<div class="box"><p>Deine Einkaufsliste ist leer.</p></div>';
      return true;
    }

    container.innerHTML = `
      <div class="rf187-einkaufsliste">
        ${liste.map((raw, index) => {
          const item = rf187ParseItem(raw);
          return `
            <label class="rf187-einkaufs-item ${item.erledigt ? "erledigt" : ""}">
              <input class="rf187-einkaufs-check" type="checkbox" ${item.erledigt ? "checked" : ""} data-index="${index}">
              <span class="rf187-einkaufs-menge">${esc187(item.menge)}</span>
              <span class="rf187-einkaufs-name">${esc187(item.name)}</span>
            </label>
          `;
        }).join("")}
      </div>
    `;

    container.querySelectorAll(".rf187-einkaufs-check").forEach(check => {
      check.addEventListener("change", () => {
        const index = Number(check.dataset.index);
        const parsed = rf187ParseItem(liste[index]);

        if (typeof liste[index] === "string") {
          liste[index] = {
            menge: parsed.menge,
            name: parsed.name,
            erledigt: check.checked
          };
        } else {
          liste[index].erledigt = check.checked;
        }

        rf187SpeichereEinkaufsliste(data.key, liste);
        rf187RenderEinkaufsliste();
      });
    });

    return true;
  }

  window.rf187RenderEinkaufsliste = function(){ return false; };

  const altAnzeigen187 = typeof einkaufslisteAnzeigen === "function" ? einkaufslisteAnzeigen : null;
  if (altAnzeigen187) {
    einkaufslisteAnzeigen = function () {
      const result = altAnzeigen187.apply(this, arguments);
      
      return result;
    };
    window.einkaufslisteAnzeigen = einkaufslisteAnzeigen;
  }

  const altToggle187 = typeof einkaufslisteToggle === "function" ? einkaufslisteToggle : null;
  if (altToggle187) {
    einkaufslisteToggle = function () {
      const result = altToggle187.apply(this, arguments);
      
      
      return result;
    };
    window.einkaufslisteToggle = einkaufslisteToggle;
  }

  function rf187BindeEinkaufsButton() {
    document.querySelectorAll("button").forEach(button => {
      const text = (button.textContent || "").toLowerCase();
      if (text.includes("einkaufsliste")) {
        if (button.dataset.rf187Bound === "1") return;
        button.dataset.rf187Bound = "1";
        const old = button.onclick;
        button.onclick = function (event) {
          const result = old ? old.call(this, event) : true;
          
          
          return result;
        };
      }
    });
  }

  window.addEventListener("load", function () {
    rf187BindeEinkaufsButton();
    
    setTimeout(rf187BindeEinkaufsButton, 800);
  });
})();



// =====================================================
// VERSION 1.88 Einkaufsliste sichtbar lassen + sicher formatieren
// =====================================================

(function () {
  function rf188ParseText(text) {
    text = String(text || "").replace(/\s+/g, " ").trim();
    const match = text.match(/^(\d+(?:[,.]\d+)?\s*[a-zA-ZäöüÄÖÜß]*)\s+(.+)$/);
    return {
      menge: match ? match[1].trim() : "",
      name: match ? match[2].trim() : text
    };
  }

  function rf188FormatExistingList() {
    const roots = [
      document.getElementById("einkaufslisteBereich"),
      document.getElementById("einkaufsliste"),
      document.querySelector(".einkaufsliste")
    ].filter(Boolean);

    roots.forEach(root => {
      const items = Array.from(root.querySelectorAll("li, .einkaufsliste-item, .einkaufslisten-item, .shopping-item"));

      items.forEach(item => {
        if (item.dataset.rf188Formatted === "1") return;

        const checkbox = item.querySelector('input[type="checkbox"]');

        // Falls schon komplexe Buttons vorhanden sind, nicht zerstören.
        const buttonCount = item.querySelectorAll("button").length;
        if (buttonCount > 0) return;

        const textOnly = Array.from(item.childNodes)
          .filter(n => n.nodeType === Node.TEXT_NODE)
          .map(n => n.textContent)
          .join(" ")
          .trim();

        let text = textOnly || item.textContent || "";
        text = text.replace(/\s+/g, " ").trim();

        if (!text) return;

        const parsed = rf188ParseText(text);

        // Nur Textknoten entfernen, Checkbox behalten
        Array.from(item.childNodes).forEach(n => {
          if (n.nodeType === Node.TEXT_NODE) n.remove();
        });

        const textWrap = document.createElement("span");
        textWrap.className = "rf188-einkauf-text";

        const menge = document.createElement("span");
        menge.className = "rf188-einkauf-menge";
        menge.textContent = parsed.menge;

        const name = document.createElement("span");
        name.className = "rf188-einkauf-name";
        name.textContent = parsed.name;

        textWrap.appendChild(menge);
        textWrap.appendChild(name);

        if (checkbox) {
          checkbox.insertAdjacentElement("afterend", textWrap);
        } else {
          item.prepend(textWrap);
        }

        item.dataset.rf188Formatted = "1";
      });
    });
  }

  window.rf188FormatExistingList = rf188FormatExistingList;

  function rf188WrapFunction(name) {
    const oldFn = window[name] || (typeof globalThis !== "undefined" ? globalThis[name] : null);
    if (typeof oldFn !== "function") return;

    const wrapped = function () {
      const result = oldFn.apply(this, arguments);
      setTimeout(rf188FormatExistingList, 0);
      setTimeout(rf188FormatExistingList, 300);
      return result;
    };

    window[name] = wrapped;
    try { globalThis[name] = wrapped; } catch(e) {}
  }

  rf188WrapFunction("einkaufslisteAnzeigen");
  rf188WrapFunction("einkaufslisteToggle");
  rf188WrapFunction("einkaufslisteRendern");

  function rf188BindButtons() {
    document.querySelectorAll("button").forEach(button => {
      const text = (button.textContent || "").toLowerCase();
      if (text.includes("einkaufsliste")) {
        if (button.dataset.rf188Bound === "1") return;
        button.dataset.rf188Bound = "1";
        const old = button.onclick;
        button.onclick = function(event) {
          const result = old ? old.call(this, event) : true;
          setTimeout(rf188FormatExistingList, 100);
          setTimeout(rf188FormatExistingList, 500);
          return result;
        };
      }
    });
  }

  window.addEventListener("load", function () {
    rf188BindButtons();
    setTimeout(rf188FormatExistingList, 500);
    setTimeout(rf188BindButtons, 1000);
  });
})();



