// =====================================================
// VERSION 1.90 Cloud-Backup einklappbar
// =====================================================

(function () {

  function rf190FindCloudBackupBereich() {

    const ids = [
      "cloudBackupBereich",
      "cloudBackup",
      "backupBereich",
      "cloudBereich"
    ];

    for (const id of ids) {
      const el = document.getElementById(id);
      if (el) return el;
    }

    const headings = Array.from(document.querySelectorAll("h1,h2,h3,h4,button,div"));

    for (const el of headings) {
      const text = (el.textContent || "").trim().toLowerCase();

      if (
        text.includes("cloud-backup anzeigen") ||
        text.includes("cloud backup anzeigen")
      ) {

        let next = el.nextElementSibling;

        while (next) {
          if (
            next.tagName !== "BUTTON" &&
            (next.children.length > 0 || next.textContent.trim())
          ) {
            return next;
          }

          next = next.nextElementSibling;
        }
      }
    }

    return null;
  }

  function rf190CreateToggle() {

    const bereich = rf190FindCloudBackupBereich();

    if (!bereich) return;

    if (document.getElementById("rf190CloudToggleButton")) return;

    const wrapper = document.createElement("div");
    wrapper.className = "rf190-cloud-toggle";

    const button = document.createElement("button");
    button.id = "rf190CloudToggleButton";
    button.type = "button";
    button.textContent = "Cloud-Backup einklappen";

    let visible = true;

    button.onclick = function () {

      visible = !visible;

      if (visible) {
        bereich.classList.remove("rf190-cloud-hidden");
        button.textContent = "Cloud-Backup einklappen";
      } else {
        bereich.classList.add("rf190-cloud-hidden");
        button.textContent = "Cloud-Backup anzeigen";
      }

      return false;
    };

    wrapper.appendChild(button);

    bereich.parentNode.insertBefore(wrapper, bereich);
  }

  window.addEventListener("load", function () {
    setTimeout(rf190CreateToggle, 500);
    setTimeout(rf190CreateToggle, 1500);
  });

})();



