// VERSION 1.95 Startseite aufräumen
// Auf der Startseite werden keine Rezepte mehr automatisch angezeigt.
// =====================================================

(function () {
  function rf195IstEinBereichOffen() {
    const ids = [
      "formularBereich",
      "rezeptSucheBereich",
      "textImportBereich",
      "einkaufBereich",
      "datenpruefungBereich"
    ];

    return ids.some(id => {
      const el = document.getElementById(id);
      if (!el) return false;
      const style = window.getComputedStyle ? window.getComputedStyle(el) : null;
      return !el.classList.contains("versteckt") && (!style || style.display !== "none");
    });
  }

  function rf195StartseiteAktivieren() {
    if (!rf195IstEinBereichOffen()) {
      document.body.classList.add("startseite-clean");
      const ergebnisse = document.getElementById("ergebnisse");
      if (ergebnisse) ergebnisse.innerHTML = "";
    }
  }

  function rf195StartseiteVerlassen() {
    document.body.classList.remove("startseite-clean");
  }

  window.rf195StartseiteAktivieren = rf195StartseiteAktivieren;
  window.rf195StartseiteVerlassen = rf195StartseiteVerlassen;

  // Alle Aktionsbuttons verlassen die saubere Startseite.
  [
    "alleRezepteToggle",
    "rezeptSucheToggle",
    "rezeptHinzufuegenToggle",
    "rezeptAssistentToggle",
    "einkaufslisteToggle",
    "datenpruefungToggle"
  ].forEach(name => {
    const fn = window[name] || (typeof globalThis !== "undefined" ? globalThis[name] : null);
    if (typeof fn === "function" && !fn.__rf195Wrapped) {
      const wrapped = function () {
        rf195StartseiteVerlassen();
        return fn.apply(this, arguments);
      };
      wrapped.__rf195Wrapped = true;
      window[name] = wrapped;
      try { globalThis[name] = wrapped; } catch(e) {}
    }
  });

  function rf195ButtonBinden() {
    document.querySelectorAll("button").forEach(btn => {
      const text = (btn.textContent || "").toLowerCase();

      if (
        text.includes("alle rezepte") ||
        text.includes("rezepte suchen") ||
        text.includes("rezept hinzufügen") ||
        text.includes("rezept-assistent") ||
        text.includes("einkaufsliste") ||
        text.includes("rezeptprüfung")
      ) {
        if (btn.dataset.rf195Bound === "1") return;
        btn.dataset.rf195Bound = "1";
        btn.addEventListener("click", rf195StartseiteVerlassen, true);
      }
    });
  }

  window.addEventListener("load", function () {
    rf195StartseiteAktivieren();
    rf195ButtonBinden();
    setTimeout(rf195StartseiteAktivieren, 300);
    setTimeout(rf195ButtonBinden, 800);
  });
})();



