(function(){

function rf200FindMainButtons(){
  const all = Array.from(document.querySelectorAll("button"));

  const main = all.filter(btn=>{
    const t=(btn.textContent||"").toLowerCase();

    return (
      t.includes("alle rezepte") ||
      t.includes("rezepte suchen") ||
      t.includes("rezept hinzufügen") ||
      t.includes("rezept-assistent")
    );
  });

  if(!main.length) return null;

  return main[0].parentElement || main[0];
}

function rf200IsBackupButton(btn){
  const t=(btn.textContent||"").toLowerCase();

  return (
    t.includes("backup") ||
    t.includes("cloud speichern") ||
    t.includes("cloud laden") ||
    t.includes("export") ||
    t.includes("import")
  );
}

function rf200CreateBackupUI(){

  if(document.getElementById("rf200BackupToggle")) return;

  const container = rf200FindMainButtons();
  if(!container) return;

  const wrapper=document.createElement("div");
  wrapper.id="rf200BackupWrapper";

  const toggle=document.createElement("button");
  toggle.id="rf200BackupToggle";
  toggle.type="button";
  toggle.textContent="Backup anzeigen";

  const panel=document.createElement("div");
  panel.id="rf200BackupPanel";

  wrapper.appendChild(toggle);
  wrapper.appendChild(panel);

  container.appendChild(wrapper);

  const buttons=Array.from(document.querySelectorAll("button"));

  buttons.forEach(btn=>{
    if(btn.id==="rf200BackupToggle") return;

    if(rf200IsBackupButton(btn)){
      panel.appendChild(btn);
    }
  });

  toggle.onclick=function(){

    const open=panel.classList.toggle("open");

    toggle.textContent=open
      ? "Backup einklappen"
      : "Backup anzeigen";

    return false;
  };
}

window.addEventListener("load", function(){
  setTimeout(rf200CreateBackupUI,300);
  setTimeout(rf200CreateBackupUI,1000);
  setTimeout(rf200CreateBackupUI,2000);
});

})();



// =====================================================
// VERSION 2.01 Backup Button fest in Startübersicht
// =====================================================

(function () {
  function rf201IsBackupButton(btn) {
    if (!btn || btn.id === "rf201BackupToggle") return false;

    const text = (btn.textContent || "").trim().toLowerCase();
    if (!text) return false;

    if (
      text.includes("rezept-assistent") ||
      text.includes("rezept speichern") ||
      text.includes("rezept hinzufügen") ||
      text.includes("rezepte suchen") ||
      text.includes("alle rezepte") ||
      text.includes("einkaufsliste") ||
      text.includes("rezepte prüfen")
    ) {
      return false;
    }

    return (
      text.includes("backup") ||
      text.includes("cloud") ||
      text.includes("export") ||
      text.includes("import")
    );
  }

  function rf201MoveBackupButtons() {
    const box = document.getElementById("rf201BackupButtons");
    if (!box) return;

    Array.from(document.querySelectorAll("button")).forEach(btn => {
      if (btn.closest("#rf201BackupPanel")) return;
      if (rf201IsBackupButton(btn)) {
        box.appendChild(btn);
      }
    });
  }

  function rf201Setup() {
    const toggle = document.getElementById("rf201BackupToggle");
    const panel = document.getElementById("rf201BackupPanel");

    if (!toggle || !panel) return;

    rf201MoveBackupButtons();

    toggle.onclick = function () {
      const isClosed = panel.classList.contains("versteckt");

      if (isClosed) {
        panel.classList.remove("versteckt");
        panel.style.display = "";
        panel.hidden = false;
        toggle.textContent = "Backup einklappen";
        rf201MoveBackupButtons();
      } else {
        panel.classList.add("versteckt");
        panel.style.display = "none";
        panel.hidden = true;
        toggle.textContent = "Backup anzeigen";
      }

      return false;
    };
  }

  window.addEventListener("load", function () {
    rf201Setup();
    setTimeout(rf201Setup, 500);
    setTimeout(rf201MoveBackupButtons, 1500);
  });
})();



// =====================================================
// VERSION 2.02 Backup Button wirklich sichtbar
// =====================================================

function rf202BackupToggle() {
  const panel = document.getElementById("rf202BackupPanel");
  const button = document.getElementById("rf202BackupToggle");

  if (!panel || !button) return false;

  const closed =
    panel.classList.contains("versteckt") ||
    panel.style.display === "none" ||
    panel.hidden;

  if (closed) {
    panel.classList.remove("versteckt");
    panel.style.display = "";
    panel.hidden = false;
    button.textContent = "Backup einklappen";
  } else {
    panel.classList.add("versteckt");
    panel.style.display = "none";
    panel.hidden = true;
    button.textContent = "Backup anzeigen";
  }

  return false;
}

window.rf202BackupToggle = rf202BackupToggle;

