// VERSION 2.46
// "Alle Rezepte anzeigen" immer alphabetisch sortieren
// =====================================================

(function () {

  function rf246SortRecipesAlphabetically(list) {
    if (!Array.isArray(list)) return [];

    return [...list].sort((a, b) => {
      const an = String(a?.name || "").toLocaleLowerCase("de");
      const bn = String(b?.name || "").toLocaleLowerCase("de");

      return an.localeCompare(bn, "de", {
        sensitivity: "base",
        numeric: true
      });
    });
  }

  function rf246ApplyAlphabeticSort() {

    // globale Ergebnislisten sortieren
    try {
      if (Array.isArray(window.letzteSuchErgebnisse)) {
        window.letzteSuchErgebnisse = rf246SortRecipesAlphabetically(window.letzteSuchErgebnisse);

        try { letzteSuchErgebnisse = window.letzteSuchErgebnisse; } catch(e) {}
      }
    } catch(e) {}

    // lokale Rezepte sortieren
    try {
      const data = JSON.parse(localStorage.getItem("rezepte") || "[]");

      if (Array.isArray(data)) {
        const sorted = rf246SortRecipesAlphabetically(data);

        window.rezepte = sorted;
        try { rezepte = sorted; } catch(e) {}

        localStorage.setItem("rezepte", JSON.stringify(sorted));
        localStorage.setItem("rezepte_rf235_sicherung", JSON.stringify(sorted));
      }
    } catch(e) {}
  }

  // bestehende Funktion erweitern
  const oldShowAll246 =
    window.rf237ShowAll ||
    window.filterAnwenden ||
    window.rezeptSucheAusfuehren;

  function showAllSorted246() {

    rf246ApplyAlphabeticSort();

    if (typeof oldShowAll246 === "function") {
      return oldShowAll246.apply(this, arguments);
    }

    return false;
  }

  window.rf246ShowAllSorted = showAllSorted246;
  window.filterAnwenden = showAllSorted246;

  try {
    filterAnwenden = showAllSorted246;
  } catch(e) {}

  function bind246() {
    document.querySelectorAll("button").forEach(button => {
      const text = (button.textContent || "").trim().toLowerCase();

      if (
        text === "alle rezepte anzeigen" ||
        text === "alle anzeigen"
      ) {
        button.type = "button";

        button.onclick = function(event) {
          if (event) {
            event.preventDefault();
            event.stopPropagation();
          }

          return showAllSorted246();
        };
      }
    });
  }

  document.addEventListener("click", function(event) {
    const button = event.target && event.target.closest ? event.target.closest("button") : null;
    if (!button) return;

    const text = (button.textContent || "").trim().toLowerCase();

    if (
      text === "alle rezepte anzeigen" ||
      text === "alle anzeigen"
    ) {
      event.preventDefault();
      event.stopPropagation();

      return showAllSorted246();
    }
  }, true);

  window.addEventListener("load", function() {
    rf246ApplyAlphabeticSort();

    bind246();

    setTimeout(bind246, 300);
    setTimeout(bind246, 1000);
  });

})();



// =====================================================
// VERSION 2.47 Kategorie-Filter Fix
// =====================================================

(function () {

  function rf247Norm(v) {
    return String(v || "")
      .trim()
      .toLocaleLowerCase("de");
  }

  function rf247GetSelectedCategories() {

    const active = [];

    document.querySelectorAll(
      "#suchKategorieKacheln .aktiv, #suchKategorieKacheln .kategorie-kachel.aktiv, #suchKategorieKacheln .such-kategorie-kachel.aktiv"
    ).forEach(el => {

      const value =
        el.dataset?.kategorie ||
        el.getAttribute("data-kategorie") ||
        el.textContent ||
        "";

      const normalized = rf247Norm(value);

      if (
        normalized &&
        normalized !== "alle" &&
        normalized !== "alle rezepte" &&
        normalized !== "alle anzeigen"
      ) {
        active.push(normalized);
      }

    });

    return [...new Set(active)];
  }

  function rf247ApplyCategoryFilter(results) {

    const selected = rf247GetSelectedCategories();

    if (!selected.length) {
      return results;
    }

    return results.filter(recipe => {

      const category = rf247Norm(
        recipe?.kategorie ||
        recipe?.category ||
        ""
      );

      return selected.includes(category);

    });

  }

  const oldSearch247 =
    window.rf237Search ||
    window.rezeptSucheAusfuehren;

  function search247() {

    if (typeof oldSearch247 === "function") {
      oldSearch247.apply(this, arguments);
    }

    let results = [];

    try {
      if (Array.isArray(window.letzteSuchErgebnisse)) {
        results = [...window.letzteSuchErgebnisse];
      }
    } catch(e) {}

    if (!results.length) {

      try {

        const data = JSON.parse(
          localStorage.getItem("rezepte") || "[]"
        );

        if (Array.isArray(data)) {
          results = data.map((r, index) => ({
            ...r,
            index
          }));
        }

      } catch(e) {}

    }

    const filtered = rf247ApplyCategoryFilter(results);

    window.letzteSuchErgebnisse = filtered;

    try {
      letzteSuchErgebnisse = filtered;
    } catch(e) {}

    try {

      if (typeof zeigeErgebnisse === "function") {
        zeigeErgebnisse(filtered);
      }

    } catch(e) {}

    const counter =
      document.getElementById("suchTrefferAnzeige");

    if (counter) {
      counter.textContent = filtered.length + " Treffer";
    }

    return filtered;
  }

  window.rezeptSucheAusfuehren = search247;
  window.rf247Search = search247;

  try {
    rezeptSucheAusfuehren = search247;
  } catch(e) {}

  function bind247() {

    document.querySelectorAll(
      "#suchKategorieKacheln .kategorie-kachel, #suchKategorieKacheln .such-kategorie-kachel"
    ).forEach(kachel => {

      if (kachel.dataset.rf247Bound === "1") return;

      kachel.dataset.rf247Bound = "1";

      kachel.addEventListener("click", function() {

        setTimeout(() => {
          search247();
        }, 60);

      });

    });

    document.querySelectorAll("button").forEach(button => {

      const text = (button.textContent || "")
        .trim()
        .toLowerCase();

      const onclick =
        button.getAttribute("onclick") || "";

      if (
        text === "suchen" ||
        onclick.includes("rezeptSucheAusfuehren")
      ) {

        button.type = "button";

        button.onclick = function(event) {

          if (event) {
            event.preventDefault();
            event.stopPropagation();
          }

          return search247();
        };
      }

    });

  }

  window.addEventListener("load", function() {

    bind247();

    setTimeout(bind247, 300);
    setTimeout(bind247, 1000);
    setTimeout(bind247, 2000);

  });

})();



// =====================================================
// VERSION 2.48 Automatische Tags für KH, Protein und Fett
// Tags:
// kh-arm / kh-reich
// protein-arm / protein-reich
// fett-arm / fett-reich
// Wird beim Speichern und rückwirkend auf gespeicherte Rezepte angewendet.
// =====================================================

(function () {
  const AUTO_TAGS_248 = new Set([
    "kh-arm", "kh-reich",
    "kohlenhydrat-arm", "kohlenhydrat-reich",
    "protein-arm", "protein-reich",
    "fett-arm", "fett-reich"
  ]);

  function $(id) {
    return document.getElementById(id);
  }

  function normalizeTag248(tag) {
    return String(tag || "")
      .toLowerCase()
      .trim()
      .replace(/\s+/g, "-")
      .replace(/proteinarm/g, "protein-arm")
      .replace(/proteinreich/g, "protein-reich")
      .replace(/kohlenhydratarm/g, "kh-arm")
      .replace(/kohlenhydratreich/g, "kh-reich")
      .replace(/kohlenhydrate-arm/g, "kh-arm")
      .replace(/kohlenhydrate-reich/g, "kh-reich")
      .replace(/kharm/g, "kh-arm")
      .replace(/khreich/g, "kh-reich")
      .replace(/fettarm/g, "fett-arm")
      .replace(/fettreich/g, "fett-reich");
  }

  function number248(value) {
    if (value === null || value === undefined) return null;
    const raw = String(value).replace(",", ".").trim();
    if (!raw) return null;
    const m = raw.match(/-?\d+(?:\.\d+)?/);
    if (!m) return null;
    const n = Number(m[0]);
    return Number.isFinite(n) ? n : null;
  }

  function readFormNumber248(id) {
    const el = $(id);
    return el ? number248(el.value) : null;
  }

  function readRecipeNumber248(recipe, keys) {
    const n = recipe && recipe.naehrwerte ? recipe.naehrwerte : {};

    for (const key of keys) {
      const val = number248(n[key]);
      if (val !== null) return val;
    }

    for (const key of keys) {
      const val = number248(recipe ? recipe[key] : null);
      if (val !== null) return val;
    }

    return null;
  }

  function macroTags248(protein, carbs, fat) {
    const tags = [];

    // Werte gelten pro 100 g
    if (protein !== null) {
      if (protein < 5) tags.push("protein-arm");
      if (protein >= 12) tags.push("protein-reich");
    }

    if (carbs !== null) {
      if (carbs < 10) tags.push("kh-arm");
      if (carbs >= 30) tags.push("kh-reich");
    }

    if (fat !== null) {
      if (fat < 5) tags.push("fett-arm");
      if (fat >= 20) tags.push("fett-reich");
    }

    return tags;
  }

  function macroTagsFromForm248() {
    const protein = readFormNumber248("eiweissInput");
    const carbs = readFormNumber248("kohlenhydrateInput");
    const fat = readFormNumber248("fettInput");

    return macroTags248(protein, carbs, fat);
  }

  function macroTagsFromRecipe248(recipe) {
    const protein = readRecipeNumber248(recipe, ["eiweiss", "eiweiß", "protein"]);
    const carbs = readRecipeNumber248(recipe, ["kohlenhydrate", "kh", "carbs"]);
    const fat = readRecipeNumber248(recipe, ["fett", "fat"]);

    return macroTags248(protein, carbs, fat);
  }

  function updateTagInput248() {
    const input = $("tagsInput");
    if (!input) return;

    const existing = String(input.value || "")
      .split(",")
      .map(normalizeTag248)
      .filter(Boolean);

    const manual = existing.filter(t => !AUTO_TAGS_248.has(t));
    const automatic = macroTagsFromForm248();

    input.value = [...new Set([...manual, ...automatic])].join(", ");
  }

  function updateRecipeTags248(recipe) {
    if (!recipe || typeof recipe !== "object") return recipe;

    const existing = Array.isArray(recipe.tags)
      ? recipe.tags.map(normalizeTag248).filter(Boolean)
      : String(recipe.tags || "").split(",").map(normalizeTag248).filter(Boolean);

    const manual = existing.filter(t => !AUTO_TAGS_248.has(t));
    const automatic = macroTagsFromRecipe248(recipe);

    recipe.tags = [...new Set([...manual, ...automatic])];
    return recipe;
  }

  function loadRecipes248() {
    try {
      const data = JSON.parse(localStorage.getItem("rezepte") || "[]");
      return Array.isArray(data) ? data : [];
    } catch(e) {
      return [];
    }
  }

  function saveRecipes248(list) {
    localStorage.setItem("rezepte", JSON.stringify(list));
    localStorage.setItem("rezepte_rf235_sicherung", JSON.stringify(list));
    window.rezepte = list;
    try { rezepte = list; } catch(e) {}
  }

  function updateAllStoredRecipes248() {
    const list = loadRecipes248();
    let changed = 0;

    list.forEach(recipe => {
      const before = JSON.stringify(recipe.tags || []);
      updateRecipeTags248(recipe);
      const after = JSON.stringify(recipe.tags || []);
      if (before !== after) changed++;
    });

    if (changed) {
      saveRecipes248(list);
      try { if (typeof dashboardAktualisieren === "function") dashboardAktualisieren(); } catch(e) {}
    }

    return changed;
  }

  const oldSave248 =
    window.rf244ApplyMacroTagsToForm ||
    window.rf241SaveWithNutritionTags ||
    window.rf235Save ||
    window.rezeptSpeichern ||
    window.rf155RezeptSpeichern;

  function saveWithAutoTags248() {
    updateTagInput248();

    // Falls rf244ApplyMacroTagsToForm nur Formular-Tags setzt, nicht als Speicherfunktion verwenden.
    let realSave =
      window.rf235Save ||
      window.rezeptSpeichern ||
      window.rf155RezeptSpeichern;

    if (realSave === saveWithAutoTags248) {
      realSave = null;
    }

    const result = typeof realSave === "function"
      ? realSave.apply(this, arguments)
      : false;

    setTimeout(updateAllStoredRecipes248, 250);
    setTimeout(updateAllStoredRecipes248, 1000);

    return result;
  }

  window.rf248UpdateTagInput = updateTagInput248;
  window.rf248UpdateAllStoredRecipes = updateAllStoredRecipes248;
  window.rezeptSpeichern = saveWithAutoTags248;
  window.rf155RezeptSpeichern = saveWithAutoTags248;
  window.rezeptSpeichernDirektCloud = saveWithAutoTags248;

  try {
    rezeptSpeichern = saveWithAutoTags248;
    rf155RezeptSpeichern = saveWithAutoTags248;
    rezeptSpeichernDirektCloud = saveWithAutoTags248;
  } catch(e) {}

  function bind248() {
    ["eiweissInput", "kohlenhydrateInput", "fettInput"].forEach(id => {
      const el = $(id);
      if (el && el.dataset.rf248Bound !== "1") {
        el.dataset.rf248Bound = "1";
        el.addEventListener("input", updateTagInput248);
        el.addEventListener("change", updateTagInput248);
      }
    });

    document.querySelectorAll("button").forEach(button => {
      const text = (button.textContent || "").trim().toLowerCase();

      if (text === "rezept speichern" || text === "speichern") {
        const oldClick = button.onclick;
        button.type = "button";
        button.onclick = function(event) {
          updateTagInput248();

          if (oldClick && oldClick !== button.onclick) {
            const result = oldClick.call(this, event);
            setTimeout(updateAllStoredRecipes248, 300);
            return result;
          }

          return saveWithAutoTags248();
        };
      }
    });
  }

  window.addEventListener("load", function() {
    const changed = updateAllStoredRecipes248();
    if (changed) console.log("v2.48 automatische KH/Protein/Fett-Tags ergänzt:", changed);

    bind248();
    setTimeout(bind248, 300);
    setTimeout(bind248, 1000);
    setTimeout(updateAllStoredRecipes248, 1500);
  });

  window.rf248Diagnose = function() {
    const list = loadRecipes248();
    return {
      rezepte: list.length,
      formularTags: $("tagsInput") ? $("tagsInput").value : "",
      beispiele: list.slice(0, 8).map(r => ({
        name: r.name,
        tags: r.tags,
        naehrwerte: r.naehrwerte
      }))
    };
  };
})();



// =====================================================
// VERSION 2.49 Suche nach Bearbeiten stabil anzeigen
// =====================================================
(function(){
  function $(id){return document.getElementById(id);}
  function esc(v){return String(v==null?"":v).replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;");}
  function norm(v){return String(v||"").toLowerCase().trim();}
  function value(id){
    const el=$(id); if(!el) return "";
    if(el.tagName&&el.tagName.toLowerCase()==="select"&&el.multiple){
      return Array.from(el.selectedOptions||[]).map(o=>o.value||o.textContent||"").join(" ");
    }
    return String(el.value||"").trim();
  }
  function loadRecipes249(){
    let list=[];
    try{list=JSON.parse(localStorage.getItem("rezepte")||"[]");}catch(e){list=[];}
    if(!Array.isArray(list)) list=[];
    list=list.filter(r=>r&&!r.geloescht&&!r.deleted&&!r.__deleted&&r.id!=="__rezeptfinder_deleted_keys__");
    window.rezepte=list; try{rezepte=list;}catch(e){}
    return list;
  }
  function ingredientsText249(r){
    const parts=[];
    if(Array.isArray(r.zutaten)){
      r.zutaten.forEach(z=>{if(typeof z==="string") parts.push(z); else if(z) parts.push([z.menge,z.einheit,z.name||z.zutat||z.text].filter(Boolean).join(" "));});
    }
    if(Array.isArray(r.zutatenGruppen)){
      r.zutatenGruppen.forEach(g=>{if(g&&g.name) parts.push(g.name); (g.zutaten||[]).forEach(z=>{if(typeof z==="string") parts.push(z); else if(z) parts.push([z.menge,z.einheit,z.name||z.zutat||z.text].filter(Boolean).join(" "));});});
    }
    return norm(parts.join(" "));
  }
  function tagsText249(r){return Array.isArray(r.tags)?norm(r.tags.join(" ")):norm(r.tags||"");}
  function selectedCategories249(){
    const active=Array.from(document.querySelectorAll("#suchKategorieKacheln .aktiv, #suchKategorieKacheln .kategorie-kachel.aktiv, #suchKategorieKacheln .such-kategorie-kachel.aktiv"));
    return active.map(el=>el.dataset?.kategorie||el.getAttribute("data-kategorie")||el.textContent||"").map(v=>String(v).trim()).filter(v=>v&&v.toLowerCase()!=="alle").map(norm);
  }
  function statusMatches249(r){
    const status=value("suchAusprobiertInput");
    if(!status) return true;
    if(status==="true") return !!r.ausprobiert;
    if(status==="false") return !r.ausprobiert;
    return true;
  }
  function renderResults249(results){
    const out=$("ergebnisse"); if(!out) return;
    out.hidden=false; out.style.display=""; out.classList.remove("versteckt");
    if(!results.length){out.innerHTML="<p>Keine Rezepte gefunden.</p>"; return;}
    out.innerHTML=results.map(r=>`
      <div class="rf249-rezeptkarte">
        <h3>${esc(r.name||"Unbenanntes Rezept")}</h3>
        <p><strong>Kategorie:</strong> ${esc(r.kategorie||"Nicht zugeordnet")}</p>
        ${r.quelle?`<p><strong>Quelle:</strong> ${esc(r.quelle)}</p>`:""}
        ${r.portionen?`<p><strong>Portionen:</strong> ${esc(r.portionen)}</p>`:""}
        <div class="rf249-aktionen">
          <button type="button" onclick="rezeptAnsehen(${r.index})">Ansehen</button>
          <button type="button" onclick="rezeptBearbeiten(${r.index})">Bearbeiten</button>
          <button type="button" onclick="rezeptLoeschen(${r.index})">Löschen</button>
        </div>
      </div>`).join("");
  }
  function search249(){
    const list=loadRecipes249();
    const nameQ=norm(value("suchNameInput"));
    const zutQ=norm(value("suchZutatenInput"));
    const tagQ=norm(value("suchTagInput")||value("suchTagsInput"));
    const quelleQ=norm(value("suchQuelleInput"));
    const cats=selectedCategories249();
    let results=list.map((r,index)=>({...r,index,vorhandene:[],fehlende:[]}));
    results=results.filter(r=>{
      const cat=norm(r.kategorie||"Nicht zugeordnet");
      return (!nameQ||norm(r.name).includes(nameQ))&&
        (!zutQ||ingredientsText249(r).includes(zutQ))&&
        (!tagQ||tagsText249(r).includes(tagQ))&&
        (!quelleQ||norm(r.quelle).includes(quelleQ))&&
        (!cats.length||cats.includes(cat))&&
        statusMatches249(r);
    });
    const sort=value("suchSortierungInput")||"name";
    if(sort==="name") results.sort((a,b)=>String(a.name||"").localeCompare(String(b.name||""),"de",{sensitivity:"base"}));
    if(sort==="kategorie") results.sort((a,b)=>String(a.kategorie||"").localeCompare(String(b.kategorie||""),"de",{sensitivity:"base"}));
    if(sort==="neu") results.sort((a,b)=>String(b.aktualisiertAm||b.erstelltAm||"").localeCompare(String(a.aktualisiertAm||a.erstelltAm||"")));
    window.letzteSuchErgebnisse=results; try{letzteSuchErgebnisse=results;}catch(e){}
    renderResults249(results);
    const counter=$("suchTrefferAnzeige"); if(counter) counter.textContent=results.length+" Treffer";
    return false;
  }
  function openSearch249(){
    document.body.classList.remove("rf205-start","startseite-clean");
    ["formularBereich","textImportBereich","einkaufBereich","datenpruefungBereich"].forEach(id=>{const el=$(id); if(el){el.hidden=true; el.style.display="none"; el.classList.add("versteckt");}});
    const search=$("rezeptSucheBereich")||$("sucheBereich");
    if(search){search.hidden=false; search.style.display=""; search.classList.remove("versteckt");}
    const out=$("ergebnisse"); if(out){out.hidden=false; out.style.display=""; out.classList.remove("versteckt");}
    loadRecipes249();
    return false;
  }
  function showAll249(){
    const list=loadRecipes249();
    const results=list.map((r,index)=>({...r,index,vorhandene:[],fehlende:[]})).sort((a,b)=>String(a.name||"").localeCompare(String(b.name||""),"de",{sensitivity:"base"}));
    window.letzteSuchErgebnisse=results; try{letzteSuchErgebnisse=results;}catch(e){}
    renderResults249(results);
    const counter=$("suchTrefferAnzeige"); if(counter) counter.textContent=results.length+" Treffer";
    return false;
  }
  window.rf249Search=search249;
  window.rf249RenderResults=renderResults249;
  window.rezeptSucheAusfuehren=search249;
  window.filterAnwenden=showAll249;
  try{rezeptSucheAusfuehren=search249; filterAnwenden=showAll249;}catch(e){}
  function bind249(){
    document.querySelectorAll("button").forEach(button=>{
      const text=(button.textContent||"").trim().toLowerCase();
      const onclick=button.getAttribute("onclick")||"";
      if(text==="rezepte suchen"){
        button.type="button"; button.onclick=function(event){if(event){event.preventDefault();event.stopPropagation();} return openSearch249();};
      }
      if(text==="suchen"||onclick.includes("rezeptSucheAusfuehren")){
        button.type="button"; button.onclick=function(event){if(event){event.preventDefault();event.stopPropagation();} return search249();};
      }
      if(text==="alle anzeigen"||text==="alle rezepte anzeigen"||onclick.includes("filterAnwenden")){
        button.type="button"; button.onclick=function(event){if(event){event.preventDefault();event.stopPropagation();} return showAll249();};
      }
    });
    ["suchNameInput","suchZutatenInput","suchTagInput","suchQuelleInput","suchAusprobiertInput","suchSortierungInput"].forEach(id=>{const el=$(id); if(el&&el.dataset.rf249Bound!=="1"){el.dataset.rf249Bound="1"; el.addEventListener("change",search249);}});
    document.querySelectorAll("#suchKategorieKacheln .kategorie-kachel, #suchKategorieKacheln .such-kategorie-kachel").forEach(k=>{if(k.dataset.rf249Bound==="1") return; k.dataset.rf249Bound="1"; k.addEventListener("click",()=>setTimeout(search249,80));});
  }
  window.addEventListener("load",function(){bind249(); setTimeout(bind249,300); setTimeout(bind249,1000); setTimeout(bind249,2000);});
  window.rf249Diagnose=function(){const out=$("ergebnisse"); return {gespeicherteRezepte:loadRecipes249().length, letzteSuchErgebnisse:Array.isArray(window.letzteSuchErgebnisse)?window.letzteSuchErgebnisse.length:null, ergebnisHtmlLaenge:out?out.innerHTML.length:null, ergebnisText:out?out.textContent.slice(0,200):""};};
})();



// =====================================================
// VERSION 2.50 Tags in der Suche aktualisieren
// Neue Tags aus gespeicherten Rezepten erscheinen im Tag-Suchfeld.
// =====================================================

(function () {
  function $(id) {
    return document.getElementById(id);
  }

  function normalizeTag250(tag) {
    return String(tag || "")
      .trim()
      .toLowerCase()
      .replace(/\s+/g, "-");
  }

  function loadRecipes250() {
    try {
      const data = JSON.parse(localStorage.getItem("rezepte") || "[]");
      return Array.isArray(data) ? data.filter(Boolean) : [];
    } catch(e) {
      return [];
    }
  }

  function collectAllTags250() {
    const tags = new Set();

    loadRecipes250().forEach(recipe => {
      if (!recipe) return;

      if (Array.isArray(recipe.tags)) {
        recipe.tags.forEach(tag => {
          const t = normalizeTag250(tag);
          if (t) tags.add(t);
        });
      } else if (typeof recipe.tags === "string") {
        recipe.tags.split(",").forEach(tag => {
          const t = normalizeTag250(tag);
          if (t) tags.add(t);
        });
      }
    });

    return [...tags].sort((a, b) =>
      a.localeCompare(b, "de", { sensitivity: "base" })
    );
  }

  function updateTagSearchDropdown250() {
    const select =
      $("suchTagInput") ||
      $("suchTagsInput");

    if (!select) return;

    const previous = Array.from(select.selectedOptions || [])
      .map(o => o.value);

    const tags = collectAllTags250();

    select.innerHTML = tags
      .map(tag => `<option value="${tag}">${tag}</option>`)
      .join("");

    Array.from(select.options || []).forEach(option => {
      if (previous.includes(option.value)) {
        option.selected = true;
      }
    });
  }

  function updateTagDatalist250() {
    const datalist = $("tagsListe");
    if (!datalist) return;

    const tags = collectAllTags250();

    datalist.innerHTML = tags
      .map(tag => `<option value="${tag}"></option>`)
      .join("");
  }

  function refreshTags250() {
    updateTagSearchDropdown250();
    updateTagDatalist250();
  }

  function refreshTagsAfterSave250() {
    setTimeout(refreshTags250, 100);
    setTimeout(refreshTags250, 500);
    setTimeout(refreshTags250, 1200);
  }

  const oldSave250 =
    window.rezeptSpeichern ||
    window.rf155RezeptSpeichern;

  function saveWithTagRefresh250() {
    let result = false;

    if (typeof oldSave250 === "function" && oldSave250 !== saveWithTagRefresh250) {
      result = oldSave250.apply(this, arguments);
    }

    refreshTagsAfterSave250();
    return result;
  }

  window.rf250RefreshTags = refreshTags250;
  window.rf250UpdateTagSearchDropdown = updateTagSearchDropdown250;
  window.rf250UpdateTagDatalist = updateTagDatalist250;

  window.rezeptSpeichern = saveWithTagRefresh250;
  window.rf155RezeptSpeichern = saveWithTagRefresh250;
  window.rezeptSpeichernDirektCloud = saveWithTagRefresh250;

  try {
    rezeptSpeichern = saveWithTagRefresh250;
    rf155RezeptSpeichern = saveWithTagRefresh250;
    rezeptSpeichernDirektCloud = saveWithTagRefresh250;
  } catch(e) {}

  function bind250() {
    refreshTags250();

    document.querySelectorAll("button").forEach(button => {
      const text = (button.textContent || "").trim().toLowerCase();

      if (text === "rezepte suchen" || text === "suchen") {
        const oldClick = button.onclick;

        button.onclick = function(event) {
          refreshTags250();

          if (oldClick && oldClick !== button.onclick) {
            return oldClick.call(this, event);
          }

          return true;
        };
      }

      if (text === "rezept speichern" || text === "speichern") {
        const oldClick = button.onclick;

        button.onclick = function(event) {
          let result = true;

          if (oldClick && oldClick !== button.onclick) {
            result = oldClick.call(this, event);
          } else {
            result = saveWithTagRefresh250();
          }

          refreshTagsAfterSave250();
          return result;
        };
      }
    });
  }

  window.addEventListener("load", function() {
    bind250();

    setTimeout(bind250, 300);
    setTimeout(bind250, 1000);
    setTimeout(refreshTags250, 1500);
  });

  window.rf250Diagnose = function() {
    const select = $("suchTagInput") || $("suchTagsInput");

    return {
      tagsAusRezepten: collectAllTags250(),
      tagsImSuchfeld: select
        ? Array.from(select.options || []).map(o => o.value)
        : []
    };
  };
})();



// =====================================================
// VERSION 2.51 Sicherer Cloud-Sync
// Audit-Ergebnis:
// Alte Cloud-Funktionen enthielten mehrere widersprüchliche Wege:
// - manche löschten vor Upload die gesamte Cloud
// - manche überschrieben beim Download lokale Rezepte komplett
// - manche konnten Upload-Loops auslösen
//
// Diese Version setzt EINEN aktiven sicheren Cloud-Pfad:
// - Upload: upsert je Rezept, KEINE komplette Cloud-Löschung
// - Download: Merge nach ID, lokale neue Rezepte bleiben erhalten
// - Manuelle Buttons werden sauber neu gebunden
// - Automatischer Upload nach Speichern bleibt deaktiviert
// =====================================================

(function () {
  let rf251CloudBusy = false;
  let rf251LastActionAt = 0;

  function $(id) {
    return document.getElementById(id);
  }

  function status251(text, error) {
    try {
      if (typeof cloudStatus === "function") {
        cloudStatus(text, !!error);
        return;
      }
    } catch(e) {}

    const el = $("cloudStatus");
    if (el) el.textContent = text;
    console.log(text);
  }

  function client251() {
    try {
      if (typeof cloudInit === "function") cloudInit();
    } catch(e) {}

    const client =
      window.supabaseClient ||
      (typeof supabaseClient !== "undefined" ? supabaseClient : null);

    if (!client) throw new Error("Supabase ist nicht verbunden.");
    return client;
  }

  function makeId251() {
    try {
      if (crypto && crypto.randomUUID) return crypto.randomUUID();
    } catch(e) {}
    return "r_" + Date.now() + "_" + Math.random().toString(16).slice(2);
  }

  function parseRecipes251() {
    try {
      const data = JSON.parse(localStorage.getItem("rezepte") || "[]");
      return Array.isArray(data) ? data : [];
    } catch(e) {
      return [];
    }
  }

  function isValidRecipe251(r) {
    return r &&
      typeof r === "object" &&
      !r.geloescht &&
      !r.deleted &&
      !r.__deleted &&
      r.id !== "__rezeptfinder_deleted_keys__";
  }

  function normalizeRecipes251(list) {
    if (!Array.isArray(list)) list = [];

    const out = [];
    const ids = new Set();

    list.forEach(r => {
      if (!isValidRecipe251(r)) return;

      if (!r.id) r.id = makeId251();

      if (ids.has(String(r.id))) {
        r.id = makeId251();
      }

      ids.add(String(r.id));

      if (!r.aktualisiertAm) {
        r.aktualisiertAm = new Date().toISOString();
      }

      out.push(r);
    });

    return out;
  }

  function saveLocal251(list) {
    list = normalizeRecipes251(list);

    localStorage.setItem("rezepte", JSON.stringify(list));
    localStorage.setItem("rezepte_rf235_sicherung", JSON.stringify(list));

    window.rezepte = list;
    try { rezepte = list; } catch(e) {}

    try { if (typeof dashboardAktualisieren === "function") dashboardAktualisieren(); } catch(e) {}
    try { if (typeof rf250RefreshTags === "function") rf250RefreshTags(); } catch(e) {}

    return list;
  }

  function timestamp251(r) {
    const t = Date.parse(r && (r.aktualisiertAm || r.aktualisiert_am || r.updated_at || r.erstelltAm || ""));
    return Number.isFinite(t) ? t : 0;
  }

  function mergeRecipes251(localList, cloudList) {
    const map = new Map();

    normalizeRecipes251(localList).forEach(r => {
      map.set(String(r.id), r);
    });

    normalizeRecipes251(cloudList).forEach(cloudRecipe => {
      const key = String(cloudRecipe.id);
      const localRecipe = map.get(key);

      if (!localRecipe) {
        map.set(key, cloudRecipe);
        return;
      }

      // Neuere Version gewinnt. Falls Zeit gleich/fehlt, lokale Version behalten.
      if (timestamp251(cloudRecipe) > timestamp251(localRecipe)) {
        map.set(key, cloudRecipe);
      }
    });

    return [...map.values()];
  }

  function recipeFromCloudRow251(row) {
    if (!row) return null;

    if (row.id === "__rezeptfinder_deleted_keys__") return null;

    if (row.daten && typeof row.daten === "object") {
      return {
        ...row.daten,
        id: row.daten.id || row.id,
        aktualisiertAm: row.daten.aktualisiertAm || row.aktualisiert_am || row.updated_at || row.daten.erstelltAm || new Date().toISOString()
      };
    }

    if (row.rezept && typeof row.rezept === "object") {
      return {
        ...row.rezept,
        id: row.rezept.id || row.id,
        aktualisiertAm: row.rezept.aktualisiertAm || row.aktualisiert_am || row.updated_at || row.rezept.erstelltAm || new Date().toISOString()
      };
    }

    return {
      id: row.id || makeId251(),
      name: row.name || "Unbenanntes Rezept",
      kategorie: row.kategorie || "Nicht zugeordnet",
      portionen: row.portionen || "",
      quelle: row.quelle || "",
      zutaten: row.zutaten || [],
      zutatenGruppen: row.zutatenGruppen || [],
      zubereitung: row.zubereitung || "",
      aktualisiertAm: row.aktualisiert_am || row.updated_at || new Date().toISOString()
    };
  }

  async function cloudUpload251() {
    const now = Date.now();

    if (rf251CloudBusy || now - rf251LastActionAt < 1500) {
      status251("Cloud-Aktion läuft bereits ...");
      return false;
    }

    rf251CloudBusy = true;
    rf251LastActionAt = now;

    try {
      const client = client251();
      const localRecipes = saveLocal251(parseRecipes251());

      if (!localRecipes.length) {
        status251("Keine lokalen Rezepte zum Hochladen.");
        return false;
      }

      status251("speichere sicher in Cloud ...");

      // WICHTIG: Keine Cloud-Komplett-Löschung mehr.
      // Nur vorhandene IDs werden aktualisiert, neue IDs werden ergänzt.
      const rows = localRecipes.map(r => {
        if (!r.id) r.id = makeId251();

        const copy = JSON.parse(JSON.stringify(r));
        copy.aktualisiertAm = copy.aktualisiertAm || new Date().toISOString();

        return {
          id: String(copy.id),
          name: copy.name || "Unbenanntes Rezept",
          daten: copy,
          aktualisiert_am: copy.aktualisiertAm || new Date().toISOString()
        };
      });

      const { error } = await client
        .from("rezepte")
        .upsert(rows, { onConflict: "id" });

      if (error) throw error;

      status251(rows.length + " Rezept(e) sicher in Cloud gespeichert.");
      if (typeof meldungAnzeigen === "function") {
        meldungAnzeigen(rows.length + " Rezept(e) sicher in Cloud gespeichert.");
      }

      return true;
    } catch(e) {
      console.error("Cloud-Speichern v2.51 Fehler:", e);
      status251("Cloud-Speichern fehlgeschlagen: " + (e.message || "unbekannter Fehler"), true);
      alert("Cloud-Speichern fehlgeschlagen: " + (e.message || "unbekannter Fehler"));
      return false;
    } finally {
      setTimeout(() => {
        rf251CloudBusy = false;
      }, 1200);
    }
  }

  async function cloudLoad251() {
    const now = Date.now();

    if (rf251CloudBusy || now - rf251LastActionAt < 1500) {
      status251("Cloud-Aktion läuft bereits ...");
      return false;
    }

    rf251CloudBusy = true;
    rf251LastActionAt = now;

    try {
      const client = client251();
      const localBefore = normalizeRecipes251(parseRecipes251());

      status251("lade sicher aus Cloud ...");

      const { data, error } = await client
        .from("rezepte")
        .select("*");

      if (error) throw error;

      const cloudRecipes = (Array.isArray(data) ? data : [])
        .map(recipeFromCloudRow251)
        .filter(Boolean);

      const merged = mergeRecipes251(localBefore, cloudRecipes);
      saveLocal251(merged);

      status251(merged.length + " Rezept(e) nach Cloud-Merge lokal verfügbar.");
      if (typeof meldungAnzeigen === "function") {
        meldungAnzeigen(merged.length + " Rezept(e) nach Cloud-Merge lokal verfügbar.");
      }

      try { if (typeof rezeptSucheAusfuehren === "function") rezeptSucheAusfuehren(); } catch(e) {}

      return true;
    } catch(e) {
      console.error("Cloud-Laden v2.51 Fehler:", e);
      status251("Cloud-Laden fehlgeschlagen: " + (e.message || "unbekannter Fehler"), true);
      alert("Cloud-Laden fehlgeschlagen: " + (e.message || "unbekannter Fehler"));
      return false;
    } finally {
      setTimeout(() => {
        rf251CloudBusy = false;
      }, 1200);
    }
  }

  async function cloudDeleteRecipe251(id) {
    if (!id) return false;

    try {
      const client = client251();
      const { error } = await client
        .from("rezepte")
        .delete()
        .eq("id", String(id));

      if (error) throw error;

      status251("Rezept aus Cloud gelöscht.");
      return true;
    } catch(e) {
      console.warn("Cloud-Löschen v2.51 fehlgeschlagen:", e);
      status251("Cloud-Löschen fehlgeschlagen: " + (e.message || "unbekannter Fehler"), true);
      return false;
    }
  }

  // Aktive Cloud-Funktionen überschreiben.
  window.rf251CloudSpeichern = cloudUpload251;
  window.rf251CloudLaden = cloudLoad251;
  window.rf251CloudRezeptLoeschen = cloudDeleteRecipe251;

  window.cloudSpeichernAlle = cloudUpload251;
  window.cloudSpeichernAlleDirekt = cloudUpload251;
  window.cloudSpeichernAlleDirekt1294 = cloudUpload251;
  window.rf215CloudSpeichern = cloudUpload251;
  window.rf217ManualUpload = cloudUpload251;
  window.rf177CloudSaveButton = cloudUpload251;

  window.cloudLaden = cloudLoad251;
  window.ausCloudLaden = cloudLoad251;
  window.cloudHerunterladen = cloudLoad251;
  window.rf240CloudLaden = cloudLoad251;
  window.rf177CloudLoadButton = cloudLoad251;

  window.cloudRezeptLoeschen = cloudDeleteRecipe251;

  try {
    cloudSpeichernAlle = cloudUpload251;
    cloudSpeichernAlleDirekt = cloudUpload251;
    cloudSpeichernAlleDirekt1294 = cloudUpload251;
    cloudLaden = cloudLoad251;
    ausCloudLaden = cloudLoad251;
    cloudHerunterladen = cloudLoad251;
    cloudRezeptLoeschen = cloudDeleteRecipe251;
  } catch(e) {}

  // Automatisches Cloud-Speichern nach lokalem Speichern deaktivieren.
  // Cloud soll bewusst über Button passieren.
  window.rf216AfterRecipeSaveUpload = function() { return false; };
  window.rf217AfterRecipeSaveUpload = function() { return false; };

  function bindCloudButtons251() {
    document.querySelectorAll("button").forEach(button => {
      const text = (button.textContent || "").trim().toLowerCase();
      const onclick = button.getAttribute("onclick") || "";

      if (
        text === "jetzt in cloud speichern" ||
        text.includes("cloud speichern") ||
        onclick.includes("cloudSpeichernAlle")
      ) {
        button.type = "button";
        button.removeAttribute("onclick");
        button.onclick = function(event) {
          if (event) {
            event.preventDefault();
            event.stopPropagation();
          }
          return cloudUpload251();
        };
      }

      if (
        text === "aus cloud laden" ||
        text.includes("cloud laden") ||
        onclick.includes("cloudLaden") ||
        onclick.includes("ausCloudLaden") ||
        onclick.includes("cloudHerunterladen")
      ) {
        button.type = "button";
        button.removeAttribute("onclick");
        button.onclick = function(event) {
          if (event) {
            event.preventDefault();
            event.stopPropagation();
          }
          return cloudLoad251();
        };
      }
    });
  }

  document.addEventListener("click", function(event) {
    const button = event.target && event.target.closest ? event.target.closest("button") : null;
    if (!button) return;

    const text = (button.textContent || "").trim().toLowerCase();

    if (text === "jetzt in cloud speichern" || text.includes("cloud speichern")) {
      event.preventDefault();
      event.stopPropagation();
      return cloudUpload251();
    }

    if (text === "aus cloud laden" || text.includes("cloud laden")) {
      event.preventDefault();
      event.stopPropagation();
      return cloudLoad251();
    }
  }, true);

  window.addEventListener("load", function() {
    bindCloudButtons251();
    setTimeout(bindCloudButtons251, 300);
    setTimeout(bindCloudButtons251, 1000);
    setTimeout(bindCloudButtons251, 2000);
  });

  window.rf251CloudDiagnose = function() {
    return {
      lokaleRezepte: normalizeRecipes251(parseRecipes251()).length,
      cloudBusy: rf251CloudBusy,
      uploadFunktion: "upsert ohne Komplett-Löschung",
      downloadFunktion: "merge lokal + cloud nach ID",
      autoUploadNachSpeichern: "deaktiviert"
    };
  };
})();



// =====================================================
// VERSION 2.52 Fix:
// 1) Cloud-Speicher-Loop endgültig blockieren
// 2) "Alle Rezepte anzeigen" funktioniert wieder alphabetisch
// =====================================================

(function () {
  let rf252ManualCloudClickUntil = 0;
  let rf252CloudBusy = false;
  let rf252LastCloudUploadAt = 0;

  function $(id) { return document.getElementById(id); }

  function rf252Status(text, error) {
    try {
      if (typeof cloudStatus === "function") {
        cloudStatus(text, !!error);
        return;
      }
    } catch(e) {}

    const el = $("cloudStatus");
    if (el) el.textContent = text;
    console.log(text);
  }

  function rf252Client() {
    try { if (typeof cloudInit === "function") cloudInit(); } catch(e) {}

    const client =
      window.supabaseClient ||
      (typeof supabaseClient !== "undefined" ? supabaseClient : null);

    if (!client) throw new Error("Supabase ist nicht verbunden.");
    return client;
  }

  function rf252MakeId() {
    try { if (crypto && crypto.randomUUID) return crypto.randomUUID(); } catch(e) {}
    return "r_" + Date.now() + "_" + Math.random().toString(16).slice(2);
  }

  function rf252LoadRecipes() {
    let list = [];
    try {
      list = JSON.parse(localStorage.getItem("rezepte") || "[]");
    } catch(e) {
      list = [];
    }

    if (!Array.isArray(list)) list = [];

    list = list.filter(r =>
      r &&
      typeof r === "object" &&
      !r.geloescht &&
      !r.deleted &&
      !r.__deleted &&
      r.id !== "__rezeptfinder_deleted_keys__"
    );

    const ids = new Set();
    list.forEach(r => {
      if (!r.id) r.id = rf252MakeId();
      if (ids.has(String(r.id))) r.id = rf252MakeId();
      ids.add(String(r.id));
    });

    window.rezepte = list;
    try { rezepte = list; } catch(e) {}

    return list;
  }

  function rf252SaveLocal(list) {
    localStorage.setItem("rezepte", JSON.stringify(list));
    localStorage.setItem("rezepte_rf235_sicherung", JSON.stringify(list));
    window.rezepte = list;
    try { rezepte = list; } catch(e) {}
  }

  function rf252IsManualAllowed() {
    return Date.now() <= rf252ManualCloudClickUntil;
  }

  async function rf252CloudUploadManualOnly() {
    // WICHTIG:
    // Nur echter manueller Buttonklick darf Cloud-Speichern auslösen.
    if (!rf252IsManualAllowed()) {
      console.warn("v2.52 blockiert automatischen Cloud-Upload.");
      return false;
    }

    const now = Date.now();

    if (rf252CloudBusy || now - rf252LastCloudUploadAt < 5000) {
      rf252Status("Cloud-Speichern läuft bereits oder wurde gerade ausgeführt.");
      return false;
    }

    rf252CloudBusy = true;
    rf252LastCloudUploadAt = now;

    try {
      const client = rf252Client();
      const list = rf252LoadRecipes();

      if (!list.length) {
        rf252Status("Keine Rezepte zum Speichern.");
        return false;
      }

      rf252Status("speichere sicher in Cloud ...");

      const rows = list.map(r => {
        if (!r.id) r.id = rf252MakeId();

        const copy = JSON.parse(JSON.stringify(r));
        copy.aktualisiertAm = copy.aktualisiertAm || new Date().toISOString();

        return {
          id: String(copy.id),
          name: copy.name || "Unbenanntes Rezept",
          daten: copy,
          aktualisiert_am: copy.aktualisiertAm
        };
      });

      const { error } = await client
        .from("rezepte")
        .upsert(rows, { onConflict: "id" });

      if (error) throw error;

      rf252SaveLocal(list);

      rf252Status(rows.length + " Rezept(e) sicher in Cloud gespeichert.");

      if (typeof meldungAnzeigen === "function") {
        meldungAnzeigen(rows.length + " Rezept(e) sicher in Cloud gespeichert.");
      }

      return true;
    } catch(e) {
      console.error("Cloud-Speichern v2.52 Fehler:", e);
      rf252Status("Cloud-Speichern fehlgeschlagen: " + (e.message || "unbekannter Fehler"), true);
      alert("Cloud-Speichern fehlgeschlagen: " + (e.message || "unbekannter Fehler"));
      return false;
    } finally {
      rf252ManualCloudClickUntil = 0;
      setTimeout(() => {
        rf252CloudBusy = false;
      }, 1500);
    }
  }

  function rf252Timestamp(r) {
    const t = Date.parse(r && (r.aktualisiertAm || r.aktualisiert_am || r.updated_at || r.erstelltAm || ""));
    return Number.isFinite(t) ? t : 0;
  }

  function rf252FromCloudRow(row) {
    if (!row || row.id === "__rezeptfinder_deleted_keys__") return null;

    if (row.daten && typeof row.daten === "object") {
      return {
        ...row.daten,
        id: row.daten.id || row.id,
        aktualisiertAm: row.daten.aktualisiertAm || row.aktualisiert_am || row.updated_at || row.daten.erstelltAm || new Date().toISOString()
      };
    }

    return {
      id: row.id || rf252MakeId(),
      name: row.name || "Unbenanntes Rezept",
      kategorie: row.kategorie || "Nicht zugeordnet",
      portionen: row.portionen || "",
      quelle: row.quelle || "",
      zutaten: row.zutaten || [],
      zutatenGruppen: row.zutatenGruppen || [],
      zubereitung: row.zubereitung || "",
      aktualisiertAm: row.aktualisiert_am || row.updated_at || new Date().toISOString()
    };
  }

  async function rf252CloudLoadMerge() {
    if (rf252CloudBusy) {
      rf252Status("Cloud-Aktion läuft bereits ...");
      return false;
    }

    rf252CloudBusy = true;

    try {
      const client = rf252Client();
      const local = rf252LoadRecipes();

      rf252Status("lade sicher aus Cloud ...");

      const { data, error } = await client
        .from("rezepte")
        .select("*");

      if (error) throw error;

      const cloud = (Array.isArray(data) ? data : [])
        .map(rf252FromCloudRow)
        .filter(Boolean);

      const map = new Map();
      local.forEach(r => map.set(String(r.id), r));

      cloud.forEach(r => {
        const old = map.get(String(r.id));
        if (!old || rf252Timestamp(r) > rf252Timestamp(old)) {
          map.set(String(r.id), r);
        }
      });

      const merged = [...map.values()];
      rf252SaveLocal(merged);

      try { if (typeof dashboardAktualisieren === "function") dashboardAktualisieren(); } catch(e) {}
      try { if (typeof rf250RefreshTags === "function") rf250RefreshTags(); } catch(e) {}

      rf252Status(merged.length + " Rezept(e) aus Cloud geladen/zusammengeführt.");

      if (typeof meldungAnzeigen === "function") {
        meldungAnzeigen(merged.length + " Rezept(e) aus Cloud geladen/zusammengeführt.");
      }

      return true;
    } catch(e) {
      console.error("Cloud-Laden v2.52 Fehler:", e);
      rf252Status("Cloud-Laden fehlgeschlagen: " + (e.message || "unbekannter Fehler"), true);
      alert("Cloud-Laden fehlgeschlagen: " + (e.message || "unbekannter Fehler"));
      return false;
    } finally {
      setTimeout(() => {
        rf252CloudBusy = false;
      }, 1200);
    }
  }

  // Automatische Cloud-Uploads unschädlich machen.
  function rf252BlockedAutoUpload() {
    console.warn("v2.52 automatischer Cloud-Upload blockiert.");
    return false;
  }

  [
    "rf216AfterRecipeSaveUpload",
    "rf217AfterRecipeSaveUpload",
    "rf217RecipeSavedUpload",
    "rezeptSpeichernDirektCloud"
  ].forEach(name => {
    try { window[name] = rf252BlockedAutoUpload; } catch(e) {}
  });

  // Cloud-Funktionen setzen.
  window.rf252CloudUpload = rf252CloudUploadManualOnly;
  window.rf252CloudLoad = rf252CloudLoadMerge;

  window.cloudSpeichernAlle = rf252CloudUploadManualOnly;
  window.cloudSpeichernAlleDirekt = rf252CloudUploadManualOnly;
  window.cloudSpeichernAlleDirekt1294 = rf252CloudUploadManualOnly;
  window.rf251CloudSpeichern = rf252CloudUploadManualOnly;
  window.rf215CloudSpeichern = rf252CloudUploadManualOnly;

  window.cloudLaden = rf252CloudLoadMerge;
  window.ausCloudLaden = rf252CloudLoadMerge;
  window.cloudHerunterladen = rf252CloudLoadMerge;
  window.rf251CloudLaden = rf252CloudLoadMerge;
  window.rf240CloudLaden = rf252CloudLoadMerge;

  try {
    cloudSpeichernAlle = rf252CloudUploadManualOnly;
    cloudSpeichernAlleDirekt = rf252CloudUploadManualOnly;
    cloudSpeichernAlleDirekt1294 = rf252CloudUploadManualOnly;
    cloudLaden = rf252CloudLoadMerge;
    ausCloudLaden = rf252CloudLoadMerge;
    cloudHerunterladen = rf252CloudLoadMerge;
  } catch(e) {}

  function rf252RenderResults(results) {
    const out = $("ergebnisse");
    if (!out) return;

    out.hidden = false;
    out.style.display = "";
    out.classList.remove("versteckt");

    if (!results.length) {
      out.innerHTML = "<p>Keine Rezepte gefunden.</p>";
      return;
    }

    function esc(v) {
      return String(v == null ? "" : v)
        .replace(/&/g, "&amp;")
        .replace(/</g, "&lt;")
        .replace(/>/g, "&gt;")
        .replace(/"/g, "&quot;");
    }

    out.innerHTML = results.map(r => `
      <div class="rf249-rezeptkarte">
        <h3>${esc(r.name || "Unbenanntes Rezept")}</h3>
        <p><strong>Kategorie:</strong> ${esc(r.kategorie || "Nicht zugeordnet")}</p>
        ${r.quelle ? `<p><strong>Quelle:</strong> ${esc(r.quelle)}</p>` : ""}
        ${r.portionen ? `<p><strong>Portionen:</strong> ${esc(r.portionen)}</p>` : ""}
        <div class="rf249-aktionen">
          <button type="button" onclick="rezeptAnsehen(${r.index})">Ansehen</button>
          <button type="button" onclick="rezeptBearbeiten(${r.index})">Bearbeiten</button>
          <button type="button" onclick="rezeptLoeschen(${r.index})">Löschen</button>
        </div>
      </div>
    `).join("");
  }

  function rf252ShowAllRecipes() {
    const list = rf252LoadRecipes()
      .map((r, index) => ({ ...r, index, vorhandene: [], fehlende: [] }))
      .sort((a, b) => String(a.name || "").localeCompare(String(b.name || ""), "de", { sensitivity: "base" }));

    window.letzteSuchErgebnisse = list;
    try { letzteSuchErgebnisse = list; } catch(e) {}

    document.body.classList.remove("rf205-start", "startseite-clean");

    ["formularBereich", "textImportBereich", "einkaufBereich", "datenpruefungBereich"].forEach(id => {
      const el = $(id);
      if (el) {
        el.hidden = true;
        el.style.display = "none";
        el.classList.add("versteckt");
      }
    });

    const search = $("rezeptSucheBereich") || $("sucheBereich");
    if (search) {
      search.hidden = false;
      search.style.display = "";
      search.classList.remove("versteckt");
    }

    rf252RenderResults(list);

    const counter = $("suchTrefferAnzeige");
    if (counter) counter.textContent = list.length + " Treffer";

    return false;
  }

  window.rf252ShowAllRecipes = rf252ShowAllRecipes;
  window.filterAnwenden = rf252ShowAllRecipes;
  try { filterAnwenden = rf252ShowAllRecipes; } catch(e) {}

  function bind252() {
    document.querySelectorAll("button").forEach(button => {
      const text = (button.textContent || "").trim().toLowerCase();
      const onclick = button.getAttribute("onclick") || "";

      if (
        text === "jetzt in cloud speichern" ||
        text === "cloud speichern" ||
        text === "in cloud speichern"
      ) {
        button.type = "button";
        button.removeAttribute("onclick");
        button.onclick = function(event) {
          if (event) {
            event.preventDefault();
            event.stopPropagation();
          }
          rf252ManualCloudClickUntil = Date.now() + 3000;
          return rf252CloudUploadManualOnly();
        };
      }

      if (
        text === "aus cloud laden" ||
        text === "cloud laden"
      ) {
        button.type = "button";
        button.removeAttribute("onclick");
        button.onclick = function(event) {
          if (event) {
            event.preventDefault();
            event.stopPropagation();
          }
          return rf252CloudLoadMerge();
        };
      }

      if (
        text === "alle rezepte anzeigen" ||
        text === "alle anzeigen" ||
        onclick.includes("filterAnwenden")
      ) {
        button.type = "button";
        button.removeAttribute("onclick");
        button.onclick = function(event) {
          if (event) {
            event.preventDefault();
            event.stopPropagation();
          }
          return rf252ShowAllRecipes();
        };
      }
    });
  }

  document.addEventListener("click", function(event) {
    const button = event.target && event.target.closest ? event.target.closest("button") : null;
    if (!button) return;

    const text = (button.textContent || "").trim().toLowerCase();

    if (
      text === "jetzt in cloud speichern" ||
      text === "cloud speichern" ||
      text === "in cloud speichern"
    ) {
      event.preventDefault();
      event.stopPropagation();
      rf252ManualCloudClickUntil = Date.now() + 3000;
      return rf252CloudUploadManualOnly();
    }

    if (
      text === "aus cloud laden" ||
      text === "cloud laden"
    ) {
      event.preventDefault();
      event.stopPropagation();
      return rf252CloudLoadMerge();
    }

    if (
      text === "alle rezepte anzeigen" ||
      text === "alle anzeigen"
    ) {
      event.preventDefault();
      event.stopPropagation();
      return rf252ShowAllRecipes();
    }
  }, true);

  window.addEventListener("load", function() {
    bind252();
    setTimeout(bind252, 300);
    setTimeout(bind252, 1000);
    setTimeout(bind252, 2000);
  });

  window.rf252Diagnose = function() {
    return {
      lokaleRezepte: rf252LoadRecipes().length,
      cloudBusy: rf252CloudBusy,
      letzterCloudUpload: rf252LastCloudUploadAt,
      manualCloudAllowed: rf252IsManualAllowed(),
      cloudUpload: "nur echter Buttonklick",
      autoUploadNachSpeichern: "blockiert"
    };
  };
})();


// =====================================================
// VERSION 2.53 Stabilisierung / Review-Fix
// Ziel: keine Funktion entfernen, aber UI-Bindings, Suche,
// Meldungen und dynamische Listen zuverlässig machen.
// =====================================================
(function () {
  "use strict";

  const STORAGE_KEY = "rezepte";
  const SAFE_KEY = "rezepte_rf235_sicherung";
  let lastMessage = { text: "", at: 0 };

  function $(id) {
    return document.getElementById(id);
  }

  function parseList(raw) {
    try {
      const parsed = JSON.parse(raw || "[]");
      return Array.isArray(parsed) ? parsed.filter(Boolean) : [];
    } catch (error) {
      console.warn("Rezepte konnten nicht gelesen werden:", error);
      return [];
    }
  }

  function loadRecipes() {
    const primary = parseList(localStorage.getItem(STORAGE_KEY));
    const backup = parseList(localStorage.getItem(SAFE_KEY));
    const list = primary.length >= backup.length ? primary : backup;
    try { rezepte = list; } catch (error) {}
    window.rezepte = list;
    return list;
  }

  function saveRecipes(list) {
    const clean = Array.isArray(list) ? list.filter(Boolean) : [];
    const json = JSON.stringify(clean);
    localStorage.setItem(STORAGE_KEY, json);
    localStorage.setItem(SAFE_KEY, json);
    try { rezepte = clean; } catch (error) {}
    window.rezepte = clean;
    return clean;
  }

  function esc(value) {
    return String(value == null ? "" : value)
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;")
      .replace(/'/g, "&#039;");
  }

  function normalized(value) {
    return String(value || "")
      .toLowerCase()
      .trim()
      .replace(/ä/g, "ae")
      .replace(/ö/g, "oe")
      .replace(/ü/g, "ue")
      .replace(/ß/g, "ss");
  }

  function asText(value) {
    if (Array.isArray(value)) return value.map(asText).join(" ");
    if (value && typeof value === "object") return Object.values(value).map(asText).join(" ");
    return String(value || "");
  }

  function selectedValues(selectId) {
    const el = $(selectId);
    if (!el) return [];
    return Array.from(el.selectedOptions || [])
      .map(option => option.value)
      .filter(Boolean);
  }

  function selectedCategoryValues(containerId) {
    const container = $(containerId);
    if (!container) return [];
    const active = Array.from(container.querySelectorAll(".aktiv"))
      .map(button => button.dataset.kategorie || "")
      .filter(Boolean);
    return active;
  }

  function showOnly(idsToShow) {
    const ids = [
      "sucheBereich",
      "rezeptSucheBereich",
      "formularBereich",
      "einkaufBereich",
      "textImportBereich",
      "datenpruefungBereich"
    ];

    ids.forEach(id => {
      const el = $(id);
      if (!el) return;
      const visible = idsToShow.includes(id);
      el.hidden = !visible;
      el.style.display = visible ? "" : "none";
      el.classList.toggle("versteckt", !visible);
    });

    document.body.classList.remove("rf205-start", "rf196-startseite", "startseite-clean");
  }

  function renderResults(results) {
    const out = $("ergebnisse");
    if (!out) return;

    out.hidden = false;
    out.style.display = "";
    out.classList.remove("versteckt");

    const count = $("suchTrefferAnzeige");
    if (count) count.textContent = `${results.length} Treffer`;

    if (!results.length) {
      out.innerHTML = "<p>Keine Rezepte gefunden.</p>";
      return;
    }

    out.innerHTML = results.map(recipe => {
      const tags = Array.isArray(recipe.tags) && recipe.tags.length
        ? `<p><strong>Tags:</strong> ${recipe.tags.map(esc).join(", ")}</p>`
        : "";
      const status = recipe.ausprobiert === true
        ? '<span class="rezept-ausprobiert status-ja">Schon ausprobiert</span>'
        : '<span class="rezept-ausprobiert status-nein">Noch nicht ausprobiert</span>';

      return `
        <article class="rf249-rezeptkarte">
          <h3>${esc(recipe.name || "Unbenanntes Rezept")}</h3>
          <p><strong>Kategorie:</strong> ${esc(recipe.kategorie || "Nicht zugeordnet")}</p>
          ${recipe.quelle ? `<p><strong>Quelle:</strong> ${esc(recipe.quelle)}</p>` : ""}
          ${recipe.portionen ? `<p><strong>Portionen:</strong> ${esc(recipe.portionen)}</p>` : ""}
          ${tags}
          ${status}
          <div class="rf249-aktionen">
            <button type="button" onclick="rezeptAnsehen(${recipe.index})">Ansehen</button>
            <button type="button" onclick="rezeptBearbeiten(${recipe.index})">Bearbeiten</button>
            <button type="button" onclick="rezeptLoeschen(${recipe.index})">Löschen</button>
          </div>
        </article>`;
    }).join("");
  }

  function sortResults(results, sortValue) {
    const sorted = [...results];
    if (sortValue === "bewertung") {
      sorted.sort((a, b) => Number(b.bewertung || 0) - Number(a.bewertung || 0));
    } else if (sortValue === "neu") {
      sorted.sort((a, b) => Date.parse(b.aktualisiertAm || b.erstelltAm || 0) - Date.parse(a.aktualisiertAm || a.erstelltAm || 0));
    } else if (sortValue === "kategorie") {
      sorted.sort((a, b) => String(a.kategorie || "").localeCompare(String(b.kategorie || ""), "de") || String(a.name || "").localeCompare(String(b.name || ""), "de"));
    } else {
      sorted.sort((a, b) => String(a.name || "").localeCompare(String(b.name || ""), "de", { sensitivity: "base" }));
    }
    return sorted;
  }

  function runSearch(showSearchPanel) {
    const list = loadRecipes();
    const nameQuery = normalized($("suchNameInput")?.value || "");
    const ingredientsQuery = normalized($("suchZutatenInput")?.value || "");
    const sourceQuery = normalized($("suchQuelleInput")?.value || "");
    const statusQuery = $("suchAusprobiertInput")?.value || "";
    const tagQueries = selectedValues("suchTagInput").map(normalized);
    const categories = [
      ...selectedCategoryValues("suchKategorieKacheln"),
      ...selectedCategoryValues("kategorienFilter")
    ];
    const uniqueCategories = [...new Set(categories)].filter(Boolean);
    const sortValue = $("suchSortierungInput")?.value || $("sortierungInput")?.value || "name";

    let results = list.map((recipe, index) => ({ ...recipe, index, vorhandene: [], fehlende: [] }));

    if (nameQuery) {
      results = results.filter(recipe => normalized(recipe.name).includes(nameQuery));
    }

    if (ingredientsQuery) {
      results = results.filter(recipe => normalized(asText(recipe.zutatenGruppen || recipe.zutaten)).includes(ingredientsQuery));
    }

    if (sourceQuery) {
      results = results.filter(recipe => normalized(recipe.quelle).includes(sourceQuery));
    }

    if (statusQuery) {
      results = results.filter(recipe => String(!!recipe.ausprobiert) === statusQuery);
    }

    if (tagQueries.length) {
      results = results.filter(recipe => {
        const recipeTags = (recipe.tags || []).map(normalized);
        return tagQueries.every(tag => recipeTags.includes(tag));
      });
    }

    if (uniqueCategories.length) {
      results = results.filter(recipe => uniqueCategories.includes(recipe.kategorie || "Nicht zugeordnet"));
    }

    results = sortResults(results, sortValue);
    window.letzteSuchErgebnisse = results;
    try { letzteSuchErgebnisse = results; } catch (error) {}

    if (showSearchPanel) showOnly(["rezeptSucheBereich"]);
    renderResults(results);
    return false;
  }

  function showAllRecipes() {
    const allButton = $("kategorienFilter")?.querySelector('[data-kategorie=""]');
    if (allButton) {
      $("kategorienFilter").querySelectorAll(".kategorie-kachel").forEach(btn => btn.classList.remove("aktiv"));
      allButton.classList.add("aktiv");
    }
    showOnly(["sucheBereich"]);
    const results = sortResults(loadRecipes().map((recipe, index) => ({ ...recipe, index, vorhandene: [], fehlende: [] })), $("sortierungInput")?.value || "name");
    window.letzteSuchErgebnisse = results;
    try { letzteSuchErgebnisse = results; } catch (error) {}
    renderResults(results);
    return false;
  }

  function refreshDynamicLists() {
    const list = loadRecipes();

    const sources = [...new Set(list.map(r => String(r.quelle || "").trim()).filter(Boolean))]
      .sort((a, b) => a.localeCompare(b, "de"));
    const tags = [...new Set(list.flatMap(r => Array.isArray(r.tags) ? r.tags : []).map(t => String(t).trim()).filter(Boolean))]
      .sort((a, b) => a.localeCompare(b, "de"));

    const sourceSelect = $("suchQuelleInput");
    if (sourceSelect) {
      const current = sourceSelect.value;
      sourceSelect.innerHTML = '<option value="">Alle Quellen</option>' + sources.map(source => `<option value="${esc(source)}">${esc(source)}</option>`).join("");
      sourceSelect.value = current;
    }

    const sourceList = $("quellenListe");
    if (sourceList) sourceList.innerHTML = sources.map(source => `<option value="${esc(source)}"></option>`).join("");

    const tagSelect = $("suchTagInput");
    if (tagSelect) {
      const current = selectedValues("suchTagInput");
      tagSelect.innerHTML = tags.map(tag => `<option value="${esc(tag)}">${esc(tag)}</option>`).join("");
      current.forEach(value => {
        const option = Array.from(tagSelect.options).find(o => o.value === value);
        if (option) option.selected = true;
      });
    }

    try { if (typeof dashboardAktualisieren === "function") dashboardAktualisieren(); } catch (error) {}
  }

  function wrapMessages() {
    if (typeof window.meldungAnzeigen !== "function" || window.meldungAnzeigen.__rf253Wrapped) return;
    const original = window.meldungAnzeigen;
    window.meldungAnzeigen = function (text, isError) {
      const now = Date.now();
      const message = String(text || "");
      if (!isError && message === lastMessage.text && now - lastMessage.at < 2500) return;
      lastMessage = { text: message, at: now };
      return original.apply(this, arguments);
    };
    window.meldungAnzeigen.__rf253Wrapped = true;
    try { meldungAnzeigen = window.meldungAnzeigen; } catch (error) {}
  }

  function bindButtons() {
    const bindings = [
      ["rf207AlleRezepte", showAllRecipes],
      ["rf207RezepteSuchen", () => { showOnly(["rezeptSucheBereich"]); refreshDynamicLists(); return false; }],
      ["rf207RezeptHinzufuegen", () => { showOnly(["formularBereich"]); if (typeof formularLeeren === "function") formularLeeren(); return false; }],
      ["rf207Einkaufsliste", () => { showOnly(["einkaufBereich"]); if (typeof einkaufslisteErstellen === "function") einkaufslisteErstellen(); return false; }],
      ["rf207RezeptAssistent", () => { showOnly(["textImportBereich"]); return false; }],
      ["rf207RezeptePruefen", () => { showOnly(["datenpruefungBereich"]); if (typeof datenqualitaetPruefen === "function") datenqualitaetPruefen(); return false; }]
    ];

    bindings.forEach(([id, handler]) => {
      const button = $(id);
      if (!button || button.__rf253Bound) return;
      button.type = "button";
      button.removeAttribute("onclick");
      button.addEventListener("click", event => {
        event.preventDefault();
        event.stopPropagation();
        handler();
      });
      button.__rf253Bound = true;
    });

    const searchButtons = Array.from(document.querySelectorAll("button"))
      .filter(button => (button.textContent || "").trim().toLowerCase() === "suchen");
    searchButtons.forEach(button => {
      if (button.__rf253SearchBound) return;
      button.type = "button";
      button.addEventListener("click", event => {
        if (!$("rezeptSucheBereich")?.contains(button)) return;
        event.preventDefault();
        event.stopPropagation();
        runSearch(true);
      }, true);
      button.__rf253SearchBound = true;
    });
  }

  function patchGlobals() {
    window.rf253ShowAllRecipes = showAllRecipes;
    window.rf253Search = () => runSearch(true);
    window.rf253RefreshLists = refreshDynamicLists;

    window.filterAnwenden = showAllRecipes;
    window.alleRezepteAnzeigen = showAllRecipes;
    window.alleRezepteStartAnzeigen = showAllRecipes;
    window.rezeptSucheAusfuehren = () => runSearch(true);

    try {
      filterAnwenden = showAllRecipes;
      alleRezepteAnzeigen = showAllRecipes;
      alleRezepteStartAnzeigen = showAllRecipes;
      rezeptSucheAusfuehren = window.rezeptSucheAusfuehren;
    } catch (error) {}
  }

  document.addEventListener("click", event => {
    const button = event.target && event.target.closest ? event.target.closest("button") : null;
    if (!button) return;

    const text = (button.textContent || "").trim().toLowerCase();
    if (button.id === "rf207AlleRezepte" || text === "alle rezepte anzeigen" || text === "alle anzeigen") {
      event.preventDefault();
      event.stopImmediatePropagation();
      showAllRecipes();
      return;
    }

    if (button.id === "rf235SaveButton" || text === "rezept speichern" || text === "speichern") {
      setTimeout(refreshDynamicLists, 150);
    }
  }, true);

  window.addEventListener("load", () => {
    wrapMessages();
    refreshDynamicLists();
    bindButtons();
    patchGlobals();
    setTimeout(() => { wrapMessages(); refreshDynamicLists(); bindButtons(); patchGlobals(); }, 300);
    setTimeout(() => { wrapMessages(); refreshDynamicLists(); bindButtons(); patchGlobals(); }, 1200);
  });

  window.rf253Diagnose = function () {
    return {
      version: "2.53",
      lokaleRezepte: loadRecipes().length,
      alleRezepteButton: !!$("rf207AlleRezepte"),
      suchButton: !!$("rf207RezepteSuchen"),
      meldungenEntprellt: !!(window.meldungAnzeigen && window.meldungAnzeigen.__rf253Wrapped)
    };
  };
})();

/* VERSION 2.55 Fix: Einkaufsliste zuverlässig zurücksetzen
   Grund: ältere Versionsblöcke verwenden teils unterschiedliche Storage-Keys
   und der v2.54-Button ruft die Funktion nur indirekt auf. */
(function () {
  function rf255SetJson(key, value) {
    try {
      localStorage.setItem(key, JSON.stringify(value));
    } catch (error) {
      console.warn('Konnte Einkaufsliste-Key nicht speichern:', key, error);
    }
  }

  function rf255RenderEmptyShoppingList() {
    const targets = [
      document.getElementById('einkaufsliste'),
      document.getElementById('einkaufslisteInhalt'),
      document.getElementById('einkaufslisteListe'),
      document.querySelector('#einkaufslisteBereich .inhalt')
    ].filter(Boolean);

    targets.forEach((target) => {
      if (target.tagName === 'UL' || target.tagName === 'OL') {
        target.innerHTML = '<li class="einkauf-leer">Die Einkaufsliste wurde gelöscht.</li>';
      } else {
        target.innerHTML = '<p class="einkauf-leer">Die Einkaufsliste wurde gelöscht.</p>';
      }
    });
  }

  window.einkaufslisteZuruecksetzen = function einkaufslisteZuruecksetzen() {
    if (!confirm('Einkaufsliste wirklich zurücksetzen?')) return;

    ['einkaufsliste', 'einkaufsListe', 'shoppingList', 'abgehakteEinkaufsliste'].forEach((key) => {
      rf255SetJson(key, []);
    });

    rf255RenderEmptyShoppingList();

    if (typeof meldungAnzeigen === 'function') {
      meldungAnzeigen('Einkaufsliste wurde zurückgesetzt.');
    }
  };

  document.addEventListener('DOMContentLoaded', function () {
    document.querySelectorAll('[data-action="reset-shopping-list"]').forEach((button) => {
      button.addEventListener('click', function (event) {
        event.preventDefault();
        event.stopPropagation();
        window.einkaufslisteZuruecksetzen();
      });
    });
  });
})();

/* VERSION 2.56 Fix: Zutaten-Zeilen im Formular zuverlässig entfernen
   Grund: ältere Fix-Blöcke entfernen nachträglich erzeugte Löschbuttons wieder.
   Dieser Block verwendet daher einen eigenen Button mit neutralem Text und
   zusätzlich ein delegiertes Click-Handling für alte X-/Löschen-Buttons. */
(function () {
  function getContainer() {
    return document.getElementById('zutatenGruppen');
  }

  function isIngredientRow(element) {
    return element && element.matches && (element.matches('.zutaten-zeile') || element.matches('.zutat-zeile'));
  }

  function removeIngredientRow(row) {
    if (!isIngredientRow(row)) return false;

    const group = row.closest('.zutatengruppe');
    row.remove();

    if (group) {
      const remainingRows = group.querySelectorAll('.zutaten-zeile, .zutat-zeile');
      const allGroups = Array.from(document.querySelectorAll('#zutatenGruppen .zutatengruppe'));

      // Die erste Gruppe bleibt immer erhalten; leere Zusatzgruppen dürfen verschwinden.
      if (!remainingRows.length && allGroups.indexOf(group) > 0) {
        group.remove();
      }
    }

    return true;
  }

  function ensureIngredientDeleteButtons() {
    const container = getContainer();
    if (!container) return;

    container.querySelectorAll('.zutaten-zeile, .zutat-zeile').forEach((row) => {
      if (row.querySelector('.rf256-zutat-entfernen')) return;

      const button = document.createElement('button');
      button.type = 'button';
      button.className = 'rf256-zutat-entfernen';
      button.textContent = 'Entfernen';
      button.title = 'Diese Zutat entfernen';
      button.setAttribute('aria-label', 'Zutat entfernen');

      row.appendChild(button);
    });
  }

  function bindObserver() {
    const container = getContainer();
    if (!container || container.dataset.rf256Observer === '1') return;

    container.dataset.rf256Observer = '1';
    const observer = new MutationObserver(() => {
      setTimeout(ensureIngredientDeleteButtons, 30);
      setTimeout(ensureIngredientDeleteButtons, 120);
    });

    observer.observe(container, { childList: true, subtree: true });
  }

  document.addEventListener('click', function (event) {
    const button = event.target && event.target.closest ? event.target.closest('button') : null;
    if (!button) return;

    const container = getContainer();
    if (!container || !container.contains(button)) return;

    const row = button.closest('.zutaten-zeile, .zutat-zeile');
    if (!row) return;

    const text = String(button.textContent || '').trim().toLowerCase();
    const isKnownDeleteButton =
      button.classList.contains('rf256-zutat-entfernen') ||
      button.classList.contains('rf239-zutat-loeschen') ||
      button.classList.contains('rf241-zutat-loeschen') ||
      button.classList.contains('rf243-zutat-loeschen') ||
      text === 'x' ||
      text === '×' ||
      text === 'entfernen' ||
      text.includes('zutat löschen') ||
      text.includes('zutat loeschen');

    if (!isKnownDeleteButton) return;

    event.preventDefault();
    event.stopImmediatePropagation();
    event.stopPropagation();
    removeIngredientRow(row);
  }, true);

  function run() {
    bindObserver();
    ensureIngredientDeleteButtons();
  }

  window.rf256EnsureIngredientDeleteButtons = ensureIngredientDeleteButtons;

  window.addEventListener('load', function () {
    run();
    setTimeout(run, 250);
    setTimeout(run, 900);
    setTimeout(run, 1800);
    setTimeout(run, 3200);
  });
})();


/* VERSION 2.57 Fix: Startseite bleibt sauber + Cloud-Backups blitzen nicht kurz auf
   - Rezeptsuche/Alle-Rezepte-Bereich wird beim Laden nicht automatisch geöffnet.
   - Backup-Inhalte sind standardmäßig unsichtbar und werden erst durch echten Klick geöffnet.
   - Cloud-Backup-Funktion bleibt erhalten: beim Öffnen wird die ursprüngliche Backup-Ladefunktion genutzt. */
(function () {
  'use strict';

  let rf257UserOpenedArea = false;
  let rf257BackupsOpen = false;

  const WORK_AREAS = [
    'sucheBereich',
    'rezeptSucheBereich',
    'formularBereich',
    'einkaufBereich',
    'textImportBereich',
    'datenpruefungBereich'
  ];

  const BACKUP_IDS = [
    'cloudBackupPanel',
    'rf222BackupBox',
    'cloudBackupListe',
    'cloudBackupContainer',
    'backupListe',
    'backupContainer',
    'cloudBackups',
    'backupBereich'
  ];

  function $(id) {
    return document.getElementById(id);
  }

  function hideElement(el) {
    if (!el) return;
    el.hidden = true;
    el.style.display = 'none';
    el.classList.add('versteckt');
    el.classList.remove('rf257-open');
  }

  function showElement(el) {
    if (!el) return;
    el.hidden = false;
    el.style.display = '';
    el.classList.remove('versteckt');
    el.classList.add('rf257-open');
  }

  function closeBackups() {
    BACKUP_IDS.forEach((id) => hideElement($(id)));
    rf257BackupsOpen = false;
    const btn = $('rf207CloudBackups');
    if (btn) btn.textContent = 'Cloud-Backups anzeigen';
  }

  function enforceStartPage() {
    if (rf257UserOpenedArea) return;

    document.body.classList.add('rf257-startseite');
    WORK_AREAS.forEach((id) => hideElement($(id)));

    const results = $('ergebnisse');
    if (results) {
      results.innerHTML = '';
      hideElement(results);
    }

    closeBackups();
  }

  function markAreaOpened() {
    rf257UserOpenedArea = true;
    document.body.classList.remove('rf257-startseite');
  }

  function findRealBackupLoader() {
    const candidates = [
      window.cloudBackupsAnzeigen_original,
      window.zeigeCloudBackups_original,
      window.backupsAnzeigen_original,
      window.cloudBackupAnzeigen_original
    ];

    for (const fn of candidates) {
      if (typeof fn === 'function' && fn !== window.rf257ToggleCloudBackups) return fn;
    }

    return null;
  }

  function moveOldBackupContentIntoPanel() {
    const panel = $('cloudBackupPanel');
    if (!panel) return;

    const oldBoxes = BACKUP_IDS
      .map((id) => $(id))
      .filter((el) => el && el !== panel && el.innerHTML && el.innerHTML.trim());

    const old = oldBoxes.find((el) => /backup|wiederherstellen|version/i.test(el.textContent || ''));
    if (old) {
      panel.innerHTML = old.innerHTML;
      hideElement(old);
    }
  }

  async function openBackups() {
    markAreaOpened();

    const panel = $('cloudBackupPanel');
    if (!panel) return false;

    showElement(panel);
    rf257BackupsOpen = true;

    const btn = $('rf207CloudBackups');
    if (btn) btn.textContent = 'Cloud-Backups ausblenden';

    panel.innerHTML = '<p>Cloud-Backups werden geladen ...</p>';

    const loader = findRealBackupLoader();
    if (loader) {
      try {
        await loader.call(window);
      } catch (error) {
        console.error('Cloud-Backups konnten nicht geladen werden:', error);
        panel.innerHTML = '<p>Cloud-Backups konnten nicht geladen werden.</p>';
      }

      setTimeout(function () {
        moveOldBackupContentIntoPanel();
        showElement(panel);
      }, 350);
    } else if (typeof window.supabaseClient === 'undefined') {
      panel.innerHTML = '<p>Cloud-Backups sind aktuell nicht verfügbar.</p>';
    }

    return false;
  }

  function toggleBackups() {
    const panel = $('cloudBackupPanel');
    const visible = rf257BackupsOpen || (panel && !panel.hidden && panel.style.display !== 'none' && panel.classList.contains('rf257-open'));

    if (visible) {
      closeBackups();
      return false;
    }

    return openBackups();
  }

  function bindStartButtons() {
    const openingIds = [
      'rf207RezepteSuchen',
      'rf207RezeptHinzufuegen',
      'rf207AlleRezepte',
      'rf207Einkaufsliste',
      'rf207RezeptAssistent',
      'rf207RezeptePruefen'
    ];

    openingIds.forEach((id) => {
      const btn = $(id);
      if (!btn || btn.dataset.rf257OpenBound === '1') return;
      btn.dataset.rf257OpenBound = '1';
      btn.addEventListener('click', markAreaOpened, true);
    });

    const backupButton = $('rf207CloudBackups');
    if (backupButton && backupButton.dataset.rf257BackupBound !== '1') {
      backupButton.dataset.rf257BackupBound = '1';
      backupButton.type = 'button';
      backupButton.onclick = null;
      backupButton.addEventListener('click', function (event) {
        event.preventDefault();
        event.stopImmediatePropagation();
        event.stopPropagation();
        toggleBackups();
      }, true);
    }
  }

  // Alte Backup-Toggle-Funktionen am Ende bewusst überschreiben.
  window.rf257ToggleCloudBackups = toggleBackups;
  window.rf222ToggleBackups = toggleBackups;
  window.rf221ToggleBackups = toggleBackups;
  window.rf220ToggleBackups = toggleBackups;
  window.rf218ToggleBackups = toggleBackups;
  window.cloudBackupsAnzeigen = toggleBackups;
  window.cloudBackupAnzeigen = toggleBackups;
  window.backupsAnzeigen = toggleBackups;
  window.zeigeCloudBackups = toggleBackups;

  // Beim ersten Render sofort schließen, dann nach alten verzögerten Fix-Blöcken erneut prüfen.
  document.addEventListener('DOMContentLoaded', function () {
    bindStartButtons();
    enforceStartPage();
  });

  window.addEventListener('load', function () {
    bindStartButtons();
    enforceStartPage();
    setTimeout(function () { bindStartButtons(); enforceStartPage(); }, 250);
    setTimeout(function () { bindStartButtons(); enforceStartPage(); }, 900);
    setTimeout(function () { bindStartButtons(); enforceStartPage(); }, 1800);
    setTimeout(function () { bindStartButtons(); enforceStartPage(); }, 3300);
  });
})();

/* VERSION 2.58 Fix: Zutatenzeile hat genau einen funktionierenden Entfernen-Button
   Entfernt alte Papierkorb-/Doppelbuttons und verhindert, dass alte Fix-Blöcke
   wieder zusätzliche Buttons in dynamisch erzeugte Zutatenzeilen schreiben. */
(function () {
  'use strict';

  const BUTTON_CLASS = 'rf258-zutat-entfernen';
  let normalizing = false;

  function container() {
    return document.getElementById('zutatenGruppen');
  }

  function rows() {
    const c = container();
    return c ? Array.from(c.querySelectorAll('.zutaten-zeile, .zutat-zeile')) : [];
  }

  function removeRow(row) {
    if (!row) return;

    const group = row.closest('.zutatengruppe');
    row.remove();

    if (group) {
      const remaining = group.querySelectorAll('.zutaten-zeile, .zutat-zeile');
      const groups = Array.from(document.querySelectorAll('#zutatenGruppen .zutatengruppe'));

      // Die erste Gruppe bleibt erhalten, leere Zusatzgruppen werden entfernt.
      if (!remaining.length && groups.indexOf(group) > 0) {
        group.remove();
      }
    }
  }

  function makeButton() {
    const btn = document.createElement('button');
    btn.type = 'button';
    btn.className = BUTTON_CLASS;
    btn.textContent = 'Entfernen';
    btn.title = 'Diese Zutat entfernen';
    btn.setAttribute('aria-label', 'Zutat entfernen');
    return btn;
  }

  function normalize() {
    if (normalizing) return;
    normalizing = true;

    try {
      rows().forEach((row) => {
        // In einer Zutatenzeile darf es genau einen Button geben: Entfernen.
        Array.from(row.querySelectorAll('button')).forEach((btn) => btn.remove());
        row.appendChild(makeButton());
      });
    } finally {
      normalizing = false;
    }
  }

  document.addEventListener('click', function (event) {
    const btn = event.target && event.target.closest ? event.target.closest('button') : null;
    if (!btn || !btn.classList.contains(BUTTON_CLASS)) return;

    const row = btn.closest('.zutaten-zeile, .zutat-zeile');
    if (!row) return;

    event.preventDefault();
    event.stopImmediatePropagation();
    event.stopPropagation();
    removeRow(row);
  }, true);

  function start() {
    const c = container();
    if (!c) return;

    normalize();

    if (c.dataset.rf258Observer === '1') return;
    c.dataset.rf258Observer = '1';

    const observer = new MutationObserver(() => {
      window.requestAnimationFrame(normalize);
    });
    observer.observe(c, { childList: true, subtree: true });
  }

  document.addEventListener('DOMContentLoaded', start);
  window.addEventListener('load', function () {
    start();
    setTimeout(normalize, 100);
    setTimeout(normalize, 400);
    setTimeout(normalize, 1200);
  });

  window.rf258NormalizeIngredientDeleteButtons = normalize;
})();
